INSERT INTO public.factions (id, name, sort_order, drop_weight, is_active)
VALUES
  ('defa02b9-c4b6-af0d-dc99-c43c278a78d8', '낭만 미식가', 1, 1.0, true),
  ('7a91727e-e2e1-b7f7-45f0-899ce04716bd', '아스팔트 레인저', 2, 1.0, true),
  ('73f0f601-2382-900c-8ca2-5cc7c93ed95d', '숲속의 갱단', 3, 1.0, true),
  ('672acbec-74d3-f36c-28e9-42563dda8e13', '셔터 마피아', 4, 1.0, true),
  ('1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', '장비병 환자들', 5, 1.0, true),
  ('e33307bb-5191-5ad5-58e0-053b40cb09f0', '비트 마에스트로', 6, 1.0, true),
  ('68f3673f-7d73-996b-b4b9-49600d0f2615', '포션 연금술사', 7, 1.0, true),
  ('d6969aef-2039-c997-4b55-a7ee861b32c5', '아날로그 수집가', 8, 1.0, true),
  ('e9e608d7-812c-4139-88c4-81d129076e3f', '작심삼일 클럽', 9, 1.0, true),
  ('24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', '미스터리 헌터', 10, 1.0, true)
INSERT INTO public.item_books (id, name, description, faction_id, is_active)
VALUES
  ('7ecbc840-6167-03a3-95b7-acca945951b1', '무명(無名)을 쫓는 야식가들', '환상의 푸드트럭 ''무명''이 도심에 남기고 간 짙은 기름 냄새를 쫓아, 포만감과 죄책감 사이를 위태롭게 질주한 낭만 미식가들의 첫 번째 궤적입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('e42446a1-d63f-f089-5fc0-c60552996d31', '위로의 탄수화물', '땀 흘린 뒤 찾아오는 밀가루의 치명적인 유혹. 팍팍한 하루를 위로하는 묵직한 포만감의 기록입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('03d35a22-9c9d-f537-031e-89d45895a089', '편의점 심야 만찬', '자정의 네온사인 아래, 급하게 채우는 플라스틱 만찬. 10km를 뛴 후 맛보는 이 조촐한 식사는 미슐랭 3스타가 부럽지 않습니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', '열대야의 극야 갈증', '열대야를 뚫고 달린 자들만이 허락받는 궁극의 시원함. 식도를 타고 흐르는 차가운 감각에 헌정하는 파편들입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('91696f3a-beb7-66f3-03c0-9398596ad56e', '시장 골목의 전설', '셔터가 내려진 전통 시장을 질주하다 우연히 발견한 심야 노포. 그곳에서 피어오르던 다정한 온기의 파편들입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('1c3530dd-94c2-b248-8967-d0016d341ebe', '업힐 끝의 단맛', '심장이 터질 듯한 오르막길의 끝, 혀끝에 닿는 찰나의 단맛을 위해 고통을 감내한 라이더들의 전리품입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('fb3adceb-50c2-9306-ea19-8fd49637d27f', '비 오는 날의 기름 냄새', '빗방울이 아스팔트를 적실 때, 본능적으로 전을 부치는 소리에 이끌린 우중 미식가들의 흔적입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('88aecafb-04e3-5a28-68ea-396f3c632fe0', '해장 라이딩의 끝', '전날의 숙취를 두 발로 밀어내며 마침내 도달한 국밥집. 영혼마저 씻어내는 뜨거운 국물의 기록입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('99553671-7ec6-08bc-56c0-af12aa326b2b', '겨울밤의 소박한 온기', '입김이 얼어붙는 영하의 밤거리, 주머니 속 3천 원이 만들어낸 소박하지만 위대한 겨울 간식 컬렉션입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('bd92067a-a33a-5848-1be4-8866e503efd2', '환상의 꼬치구이 트럭', '무명 트럭의 숨겨진 쌍둥이, 매주 금요일 밤에만 나타난다는 연기 자욱한 꼬치구이 트럭의 비밀 레시피입니다.', 'defa02b9-c4b6-af0d-dc99-c43c278a78d8', false),
  ('e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', '블랙 트랙의 생존자', '도시가 가장 험악한 얼굴을 할 때 이들은 미소 짓습니다. 폭우와 한파 속에서 전설의 루트 ''블랙 트랙''의 입구를 밟아낸 증거들입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', '폭우 속의 질주', '하늘이 구멍 난 듯 쏟아지는 장대비를 뚫고 나아간 미치광이들. 젖은 아스팔트가 남긴 물비린내 나는 파편들입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('e14da4c2-53c0-37c1-8816-3ec48a0dcd23', '영하 15도의 호흡', '모든 것이 얼어붙는 한파 속, 오직 심장 박동만이 끓어오르는 자들이 내뱉은 거친 입김의 결정체입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('7ba44a13-fece-0409-75c4-5a36676c1fdf', '진흙탕의 영광', '포장도로를 버리고 기꺼이 야생의 오프로드로 뛰어든 자들. 진흙투성이가 된 채 웃음 짓는 영광의 훈장들입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('102322b0-8735-86a1-5eb6-b0423f116e42', '야간 산악 행군', '가로등 하나 없는 칠흑 같은 산길, 오직 헤드랜턴 한 줄기 빛에 의지해 밤을 지새운 야간 행군의 잔해들입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('06f0dba2-805b-4631-8a3f-4111fa88db7c', '망가진 기어들의 무덤', '한계를 시험하다 장렬히 전사한 기어들. 이들이 남긴 망가진 부품들은 역설적으로 가장 치열했던 순간을 증명합니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('bc33de8f-7f87-ee74-1680-c0a09008a04a', '아스팔트 열기', '아스팔트가 녹아내리는 한여름 한낮의 폭염. 지열을 온몸으로 받아내며 달린 태양의 전사들이 남긴 녹아내린 유물들입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('7a3b59a7-2cca-f2c2-11bd-73e73564087c', '상처뿐인 영광', '넘어지고 구르고 찢어져도 다시 일어난 자들. 육체의 고통을 훈장처럼 여기는 거친 레인저들의 응급처치 키트입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('b8d5d84e-9819-02f8-d302-15b7cccac325', '생존 배낭의 밑바닥', '며칠 밤낮을 걷는 혹독한 여정의 끝, 텅 빈 생존 배낭 밑바닥에 굴러다니던 마지막 희망의 조각들입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('a44e3e21-9b4b-ba10-130e-3fb6b270702d', '태풍의 눈', '모두가 대피하는 태풍 경보의 날, 거센 바람과 맞서 싸우기 위해 밖으로 나간 미친 자들의 폭풍 궤적입니다.', '7a91727e-e2e1-b7f7-45f0-899ce04716bd', false),
  ('68a6ef7d-8ef3-117b-b25c-1418e1c5d416', '그루터기 살롱의 장물들', '인간들의 방심을 틈타 가방을 털고 간 무법자들의 전리품. 깊은 숲속 그루터기 살롱에서 도토리와 밀거래되고 있습니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('27249944-6e0c-081a-6df2-8b5fd57d31df', '공원 벤치의 포식자', '평화로운 점심시간, 방심하고 벤치에 둔 인간들의 도시락을 순식간에 털어간 도심 비둘기와 참새 마피아의 흔적입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('93a53906-a042-cff2-77de-0a3ca8da5eae', '골목길 마피아의 회합', '달빛이 비치는 뒷골목, 쓰레기봉투를 뜯으며 구역을 나누는 길고양이 보스들의 은밀한 회합 장소 단서들입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('0ee39bb4-b882-1524-49fe-18879115d396', '다람쥐의 월동 준비', '겨울이 오기 전, 숲속 은행나무와 참나무 아래를 바쁘게 누비며 뺨을 빵빵하게 채운 다람쥐 조직원들의 비상식량 창고입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('1407bbea-f57a-aa97-2dce-c6ec834bec1c', '까치의 반짝이는 보물', '유독 반짝이는 인간의 물건에 집착하는 까치 도둑들. 둥지 깊숙한 곳에 숨겨둔 그들만의 기묘한 보물 컬렉션입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('1d5c6b3a-8498-71bb-a1db-87b02032013e', '들개의 은밀한 사냥', '인적이 끊긴 교외의 밤, 야성을 되찾은 들개 무리가 남긴 위협적이면서도 쓸쓸한 야생의 흔적들입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('876f9690-6308-5dca-5bea-4c197dade0cd', '도심 숲의 불청객', '잘 가꿔진 공원 생태계를 교란시키는 불청객들. 꿀을 노리는 말벌과 과일을 훔치는 너구리들의 소동 흔적입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('6fc07713-c620-5fe8-dac1-475de83976d2', '은밀한 밤의 무도회', '인간들이 모두 잠든 깊은 밤 숲속, 곤충들과 작은 동물들이 벌이는 비밀스러운 야간 축제의 화려한 흔적들입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('3a7f3fa1-08de-ad46-8c03-ac0ada645054', '그루터기 살롱의 VIP', '숲속 갱단 중에서도 서열이 높은 우두머리들만이 거래할 수 있다는 최상급 장물들. 인간 세계에서도 찾기 힘든 물건들입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('75cb518f-77c2-b1af-4d11-e0843c7517e5', '겨울잠의 안식처', '길었던 활동을 마치고 깊은 겨울잠에 빠져드는 동물들의 따뜻하고 푹신한 은신처에서 떨어져 나온 포근한 파편들입니다.', '73f0f601-2382-900c-8ca2-5cc7c93ed95d', false),
  ('ad1a2ef7-4499-0773-f0c8-ba31e96087f2', '노을 헌터의 기록', '붉게 물드는 단 15분의 마법을 담기 위해 한강 다리 위를 숨 가쁘게 달린 자들의 유실물입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', '비밀의 카페 탐험', '산골짜기 숨겨진 뷰 맛집 카페를 찾아 업힐을 등반한 인증샷러들이 남긴 향긋한 흔적들입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('436bb10f-68c3-4846-158b-fc7d3a62e674', '새벽 물안개 몽환', '새벽 4시, 호숫가에 피어오르는 물안개의 몽환적인 샷을 건지기 위해 밤잠을 포기한 흔적들입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('d094bab5-0ca9-2200-f188-424be9a00b47', '도심 야경의 불빛', '도시의 네온사인이 그리는 빛의 궤적(장노출)을 찍으려 삼각대와 함께 육교 위에서 버틴 시간들입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('7f745d9d-0f5f-23da-c024-aeaa94af139e', '잊혀진 폐허의 미학', '인적이 끊긴 철길이나 오래된 폐공장의 스산한 분위기를 피드에 올리기 위해 탐험한 용감한 마피아들.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('3d3b35f4-f380-22f6-568b-514444111042', '봄꽃 출사 전쟁', '벚꽃이 만개한 주말, 인파를 뚫고 오직 꽃과 나만의 구도를 찾기 위해 치열한 눈치싸움을 벌인 흔적입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('918d9a0a-ce3d-0044-8f55-c6dff8d627ac', '가을 단풍 터널', '불타는 단풍나무 아래로 자전거를 타고 달리는 인생 영상을 건지기 위해 고프로를 달고 달린 자들입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('b81489b0-383c-0956-ec43-921031148e04', '눈 덮인 순백의 언덕', '발자국 하나 없는 완벽한 설원을 찍기 위해 무릎까지 빠지는 눈밭을 기어 올라간 헌터들의 동상 걸린 기록.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('31a58a77-acff-58c9-93b5-0d3ac046aaa6', '골목길 필름 스냅', '최신 디지털 대신 빈티지 필름 카메라를 들고, 재개발 동네의 옛 정취를 담아낸 아날로그 감성들입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('321e6f64-f01d-d74e-9824-a80843e36d0e', '매직 아워 25시', '하루에 존재하지 않는 시간, 가장 완벽한 보랏빛 노을이 지는 환상의 차원에 진입한 자들의 전리품입니다.', '672acbec-74d3-f36c-28e9-42563dda8e13', false),
  ('f3e7e637-1f47-569a-014a-4cca4c0fe691', '카본의 유혹', '지갑을 털어 무게를 10g 줄일 때마다 엄청난 아드레날린을 느끼는 카본 맹신도들의 파편입니다.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('570da6fc-a0b4-4565-011c-5621a9fcb217', '티타늄 맹신', '은은하게 빛나는 티타늄 특유의 색감에 미쳐, 나사 하나까지 티타늄으로 바꾸는 자들의 흔적입니다.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('9232c1ce-cbc6-d314-4739-08b4ceae84c5', '신상 언박싱의 희열', '해외 직구로 3주를 기다린 신상 기어를 택배로 받아 뜯는 그 순간의 흥분과 잔해들입니다.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('31b5587e-d58e-3630-06d9-8a7665ba2ad0', '당근의 잠복자', '', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('eff21028-8cbc-cce2-4c88-55fdd156d94b', '공구통의 비밀', '자전거를 타는 시간보다 분해하고 조립하는 시간이 더 긴 방구석 미캐닉들의 끈적한 유물입니다.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', '에어로다이나믹의 노예', '공기 저항을 1와트라도 줄이기 위해 몸에 꽉 끼는 옷을 입고 고통받는 공기역학 맹신도들.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('5ad4b074-f41c-8d6f-271c-38bff6551fe8', '구동계 업그레이드 병', '기계식에서 전자식으로, 무선으로 끊임없이 변속기를 바꾸며 만족을 모르는 자들의 흔적.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('cd526b91-4088-303d-f157-2db59e663f4d', '세차 광신도', '장비에 묻은 먼지 한 톨을 용납하지 못해, 매일 칫솔을 들고 프레임을 닦아대는 결벽증 유저들.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', '지름신 강림', '어느 날 갑자기 찾아온 ''지름신''의 계시를 받고 앞뒤 보지 않고 최상급 기어를 결제해 버린 순간.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('82537749-38f9-ca1e-40f2-df95bc6ea05b', '카본 앨리의 입장권', '가벼워지기 위해 영혼마저 거래한다는 심야의 비밀 암시장, ''카본 앨리''에 진입한 자들만이 줍는 파편.', '1d75e1ea-ad3c-b2e8-a8a3-0a062fc3e41d', false),
  ('e5036bea-62f5-2124-3ce3-00b9a4a56970', '180 BPM의 심장', '러닝 페이스를 철저히 180 BPM 음악에 맞춰 쪼개는 리듬의 노예들이 흘리고 간 비트의 파편들입니다.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('0b57f851-6ed6-9ab4-5ad6-17a5732dd802', '노이즈 캔슬링 세상', '외부 소음을 완벽히 차단하고 오직 자신만의 세계에 빠져 질주하다 놓쳐버린 바깥세상의 조각들.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('2ca773eb-0497-42d9-55ba-38ef994a86b1', '새벽의 Lo-Fi', '아무도 없는 새벽 안개 속, 차분한 로파이 비트를 들으며 명상하듯 달린 마에스트로의 감성.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('af495f17-d454-01d5-7f12-1c437ad945e3', '업힐의 하드락', '심장이 터질 것 같은 오르막길을 데스메탈과 하드락의 강렬한 기타 리프로 버텨낸 광기의 흔적.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('76e66f30-a4a1-0f10-0b9d-ba256f4411c5', '배터리 방전의 공포', '음악이 끊기면 달릴 수 없는 자들에게, 이어폰 배터리 5% 알림은 사형 선고와 같습니다.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('034f75b5-d39d-dfad-d2e9-058295089aa0', '러너스 하이 EDM', '고통이 환희로 바뀌는 순간, 뇌 속에서 폭발하는 EDM 비트를 시각화한 형형색색의 파편들.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('93c93225-cd68-8b93-a56d-f7494955ac01', '아날로그 믹스테이프', '스트리밍을 거부하고 카세트 워크맨을 들고 달리는 레트로 마니아들의 늘어진 테이프 자국.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('add1460a-b2e0-e3c3-ef88-3faaaf098940', '플레이리스트 공유', '길을 가다 마주친 러너와 플레이리스트를 에어드랍으로 교환한 훈훈한 소셜 네트워킹의 흔적.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('46557b9f-ebf9-58f6-33a7-47067847ced1', '빗속의 클래식', '비 오는 날 아스팔트 위를 달리며 장엄한 오케스트라 클래식을 듣는 우수에 찬 마에스트로.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('0a4db403-be8c-d32c-e496-af02de24687d', '노이즈 캔슬링 0', '모든 외부 소음이 사라지고 오직 우주의 주파수와 심장 박동만이 동기화된 절대 영점의 차원.', 'e33307bb-5191-5ad5-58e0-053b40cb09f0', false),
  ('6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', '카페인 과부하', '잠을 쫓고 한계를 넘기 위해 카페인을 혈관에 직접 쏟아부은 아웃도어 도핑 전문가들의 흔적입니다.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', '전해질 밸런스', '땀으로 빠져나간 나트륨과 칼륨을 완벽한 비율로 보충하기 위해 연구실처럼 세팅한 배합의 결과물.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('e10b45ea-80e8-e382-d2ac-c8e599fe83fe', '회복의 마법약', '근육통을 없애기 위해 운동 직후 30분 이내에 BCAA와 단백질을 우겨넣는 리커버리 맹신도.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', '불법 부스터 배합', '', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', '젤의 늪', '자전거 뒷주머니에 넣어둔 에너지 젤이 터져 옷과 손이 끈적해진 지옥 같은 라이딩의 파편들.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', '숙취와 포션', '전날 마신 술을 땀으로 빼겠다며 달리기 시작했으나, 결국 해장 포션만 찾아 헤맨 슬픈 영혼.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('9fa66456-8cf3-a2df-39e0-5b86c0917449', '극한의 갈증', '물통을 안 챙기고 출발했다가 목이 말라 쓰러지기 직전, 사막의 오아시스처럼 편의점을 발견한 순간.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('b2eb6a30-d721-42a5-7c87-c499e3fe6392', '비타민 폭탄', '몸에 좋다는 건 다 챙겨 먹는 건강염려증 환자들의 가방에서 쏟아져 나온 알록달록한 알약들.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('8134d134-2c0f-74cd-5421-0406a23f30a6', '마지막 스퍼트의 묘약', '결승전 1km를 앞두고 주머니에 아껴둔 가장 강력하고 비싼 마지막 포션을 들이킨 헌터.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('bf20a6e1-d3e3-989c-b2db-795287c711d6', '오아시스 자판기의 동전', '환상의 음료를 뽑기 위해 4차원에만 존재한다는 ''오아시스 자판기''에 넣어야 할 고대 동전들.', '68f3673f-7d73-996b-b4b9-49600d0f2615', false),
  ('5fe3f8eb-970b-9847-dbfa-9773337c27d5', '잃어버린 시간', '스마트워치를 끄고, 똑딱거리는 태엽 초시계 하나에 의지해 자신만의 속도로 달린 낭만주의자들.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('af74bb10-30c7-603d-c6f9-cf7f95533f58', '행운의 잡동사니', '길거리를 뛰다 발견한 반짝이는 쓰레기들을 행운의 부적이라 믿고 주머니에 모은 까마귀 같은 유저들.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('1b20a1db-9bbb-f790-572b-a4da8622eb92', '종이 지도의 낭만', 'GPS 내비게이션 대신 종이 지도를 보며 길을 헤매는 것을 모험이라 부르는 아날로그 길치들.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('c79fc13c-4edc-a47e-75b6-5aa613958116', '빛바랜 사진의 추억', '최신 스마트폰 카메라 대신 낡은 폴라로이드나 일회용 카메라로 풍경을 담은 따뜻한 흔적들.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('a92d8af5-78cc-9d19-738f-9b6897f0f6d7', '할아버지의 유품', '대를 이어 물려받은 낡은 등산 지팡이나 오래된 자전거를 고쳐 타며 과거와 교감하는 수집가.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('79ab7cbd-a18e-d9d3-d340-940bece93f32', '길거리 우체통의 편지', '누구에게 가는지 모를 반송된 편지나 길바닥에 떨어진 누군가의 일기장 한 페이지.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', '고장난 장난감의 슬픔', '놀이터 구석이나 골목길에 버려진 주인을 잃은 낡은 장난감들을 거둬준 따뜻한 마음.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('d564cbd5-c667-7c03-e55c-90c83d228add', '사라진 동네의 기록', '재개발로 사라지는 동네 골목을 누비며, 곧 부서질 벽돌과 간판의 조각을 수집하는 기록자들.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('e6399dcb-6a46-48e5-3251-7a1493d5f55d', '헌책방의 냄새', '헌책방 골목을 걷다 발견한, 누군가 밑줄을 그어놓은 오래된 소설책의 찢어진 페이지들.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('8405301c-5dfe-4e35-55f6-1d869d1a1a91', '분실물 센터 999', '세상의 모든 잃어버린 기억들이 모여 안식을 취하는 4차원의 보관소, ''999번 방''을 여는 열쇠.', 'd6969aef-2039-c997-4b55-a7ee861b32c5', false),
  ('9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', '내일의 러너', '이불 밖은 위험하다며 오늘 러닝을 내일로 미룬 채, 마음속으로만 마라톤을 완주한 자들의 핑계거리.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('8fbd67f1-27d9-39de-4f75-d44628a2d7dc', '먼지 쌓인 홈트 기구', '거실 한구석에서 빨래 건조대로 전락해버린 실내 자전거와 먼지 쌓인 덤벨들의 슬픈 파편.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('c0f08c17-27fd-d830-bc7c-ad928a7387f9', '쇼핑만 프로 선수', '운동은 시작도 안 했으면서 최상급 장비와 의류만 잔뜩 사놓고 장비병 환자 흉내를 내는 자들.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('c038d31d-68de-b808-7a0f-7251d3373f53', '회식의 변명', '오늘 저녁 운동을 가려 했으나, ''어쩔 수 없는'' 팀 회식 때문에 삼겹살 집으로 발길을 돌린 직장인.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', '날씨 탓 전문가', '비가 와서, 미세먼지가 많아서, 너무 더워서, 너무 추워서. 365일 중 360일을 날씨 탓으로 쉬는 자들.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('ffe967a2-e423-1a20-7016-25c300a540c2', '헬스장 기부 천사', '', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('989fc342-1d1d-4b82-657d-81a7190df782', '스마트폰의 노예', '운동화 끈을 묶고 유튜브 쇼츠를 하나만 보려다, 결국 2시간 동안 소파에 앉아있던 허무한 시간.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('6cca30db-b0b2-48d3-bcb9-9de34491f063', '3일 차의 위기', '작심삼일의 고비인 3일째 되는 날. 온몸이 쑤시고 의지력이 바닥나며 결국 침대와 타협해 버린 흔적.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('6d5e8172-a74c-8b22-7952-7ff95ea566af', '내일부터 진짜 다이어트', '최후의 만찬이라며 치킨을 시켜 먹고, 항상 다이어트는 ''내일''부터라고 외치는 평행우주의 반복.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('2ca772e9-1ef9-938a-f793-b8e0e75c4914', '결계 ''섬데이'' 돌파', '영원히 반복되는 ''내일(Someday)''의 환상 결계를 깨고, 기적처럼 현관문을 열고 나간 승리의 순간.', 'e9e608d7-812c-4139-88c4-81d129076e3f', false),
  ('e8af7880-700b-5070-7c59-af45a2b4b7db', '차원의 틈새', '심장이 터질 듯한 고통의 임계점(러너스 하이)을 넘는 순간, 잠깐 열린 4차원 틈새에서 주워 온 유물들.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', '미확인 생명체의 흔적', '심야의 깊은 산속 행군 중, 도저히 지구상의 동물이라고 볼 수 없는 기묘한 발자국과 마주친 기록.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('f0991102-e59b-9d99-a61f-6a547814c1bc', '중력 이상 지대', '업힐을 오르는데 갑자기 페달이 가벼워지고, 내리막에서 오르막처럼 힘든 기묘한 중력 역전 현상.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', '심야의 도깨비 불', '', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('5122e7e5-3356-f8f5-4891-468556cc1e75', '평행우주의 기억', '분명 처음 온 길인데 너무나 익숙하고, 내가 아닌 다른 차원의 나의 기억이 덧씌워지는 데자뷔 현상.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('6ef1c7fd-2973-43d2-912c-d37eed254b60', '시간의 미로', '10분밖에 안 달린 것 같은데 3시간이 지나 있고, GPS 트랙이 엉망으로 꼬여버린 시간의 사각지대.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('4dbe2c2a-2a77-e70d-4790-0770b60050fb', '침묵의 메아리', '가장 시끄러운 도심 한복판에서, 갑자기 세상의 모든 소리가 ''음소거''된 듯한 완벽한 기이한 진공 상태.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('4cec3af4-2067-9e4f-1e2a-e0472f381b08', '환각의 안개 숲', '안개 낀 숲길을 걷다 나무들이 살아 움직이고 돌들이 말을 거는 듯한 강렬한 환각에 빠진 탐험가.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('689bb588-c6f6-b417-169a-6648aac77b85', '고통의 초월자', '육체의 고통이 극에 달한 순간, 통증이 사라지고 육체와 분리되어 자신을 내려다보는 유체이탈의 경험.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false),
  ('2a8f481e-77ba-1876-c15c-5fc9965189f4', '화이트 룸의 문', '모든 미스터리의 종착지, 육체의 고통을 넘어선 무의식의 차원 ''화이트 룸''에 잠시 들어갔다 나온 증거.', '24d7af8e-a4ef-8798-a7f1-f1f2d6c9d582', false)
INSERT INTO public.badges (name, description, type, rarity, item_book_id, drop_weight)
VALUES
  ('매콤달콤 떡볶이', '스트레스를 단숨에 녹여버리는 마법의 붉은 소스. 라이딩 후 먹으면 칼로리가 0이 된다는 전설이 있습니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('한 입 베어문 핫도그', '누군가 다급하게 한 입 먹고 출발한 흔적. 케첩과 머스터드의 황금 비율이 돋보이는 명작입니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('황금 슈크림 붕어빵', '팥파와 슈크림파의 오랜 전쟁을 단숨에 종식시킬 만큼 완벽하게 바삭하게 구워진 전설의 붕어빵입니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('반으로 갈라진 나무젓가락', '야식의 문을 여는 열쇠. 완벽하게 정확히 5:5로 갈라져 있어 오늘 밤 엄청난 행운을 예고합니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('기름 묻은 종이봉투', '가슴속에 3천 원을 품고 다녀야 하는 이유. 은은한 튀김 냄새가 배어 있어 후각을 사정없이 자극합니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('식어버린 타코야끼', '입천장을 데일 뻔한 위기를 넘기고 차갑게 식어버린 비운의 간식. 하지만 가다랑어포의 풍미는 여전합니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('바닥난 양념치킨 소스', '마지막 한 방울까지 싹싹 긁어먹은 흔적. 혀끝에 맴도는 달콤함이 러닝의 고통을 잊게 해줍니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('길거리 트럭 뻥튀기', '''뻥!'' 소리와 함께 탄생한 고소한 원반. 공기 반, 탄수화물 반으로 이루어진 기적의 다이어트 식품입니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('마지막 남은 어묵 국물', '찬 바람 부는 밤, 얼어붙은 영혼마저 따뜻하게 녹여주는 마법의 물약 엑기스입니다.', 'item', 'common', '7ecbc840-6167-03a3-95b7-acca945951b1', 1.0),
  ('꼬들한 라면 면발', '퍼진 면을 극혐하는 미식가가 정확히 3분 30초만 끓여낸 궁극의 탄성. 땀 흘린 뒤 최고의 보상입니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('옆구리 터진 김밥', '재료를 너무 욕심내어 그만 배가 터져버린 김밥. 터져 나온 햄과 단무지가 오히려 식욕을 자극합니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('바삭한 오징어튀김', '아스팔트 위를 구르면서도 튀김옷의 바삭함을 잃지 않은 끈질긴 생명력의 소유자입니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('기름진 볶음밥', '중화요리 고수의 웍(Wok)에서 불향을 가득 머금고 탄생한 황금빛 탄수화물 산더미입니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('마요네즈 묻은 젓가락', '칼로리 폭탄의 현장을 증명하는 유력한 증거물. 핥아 먹고 싶은 충동을 간신히 참아냈습니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('단무지 한 조각', '모든 기름진 음식의 영원한 구원자. 아삭하는 경쾌한 소리가 귓가에 맴도는 듯합니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('식어버린 짜장 소스', '당구장, 혹은 한강 공원 돗자리 위에서의 치열했던 식사 전투가 끝난 뒤 남겨진 달콤한 흔적입니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('군만두 간장 팩', '항상 뜯을 때 손에 묻어 짜증을 유발하지만, 결코 없어서는 안 될 감초 같은 존재입니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('구겨진 배달 영수증', '''라이더님 조심히 오세요''라는 다정한 멘트와 함께, 지갑이 얇아졌음을 알리는 슬픈 증서입니다.', 'item', 'common', 'e42446a1-d63f-f089-5fc0-c60552996d31', 1.0),
  ('삼각김밥 껍질', '참치마요의 짭짤한 기억만 남기고 장렬히 전사한 비닐 껍데기. 뜯는 선을 완벽하게 맞췄습니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('전자레인지에 데운 핫바', '전자레인지 안에서 30초 동안 팽창하며 육즙을 한껏 머금은, 편의점 심야 식당의 에이스입니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('바나나맛 우유 뚜껑', '초록색 은박을 손가락으로 뽕! 뚫어 먹어야 제맛이라는 옛 낭만주의자들의 고집이 담겨 있습니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('차가운 도시락 용기', '자정의 네온사인 불빛 아래, 누군가의 허기진 배를 든든하게 채워주고 남은 플라스틱 빈 용기입니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('2+1 행사 바코드', '자본주의의 달콤한 유혹. 하나만 사려다 결국 세 개를 들고 나오게 만드는 무서운 마법진입니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('구겨진 캔맥주', '10km 러닝 후 단숨에 들이켠 맥주의 시원함. 찌그러진 알루미늄에서 짜릿한 목 넘김이 전해집니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('매운 컵라면 용기', '땀구멍을 강제 개방시키는 매운맛의 잔해. 국물을 다 마실까 말까 수백 번 고민한 흔적이 보입니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('플라스틱 숟가락', '도시락을 먹기 위해 필수적인 도구. 끄트머리에 묻은 소스 한 방울이 아련하게 남아 있습니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('검은 비닐봉지', '편의점에서 산 야식을 은밀하게 품고 달리던 자의 흔적. 바람에 날려 아스팔트 위를 뒹굴고 있습니다.', 'item', 'common', '03d35a22-9c9d-f537-031e-89d45895a089', 1.0),
  ('성에 낀 생맥주잔', '냉동실에서 갓 꺼낸 잔에 담겨있던 시원함의 결정체. 보는 것만으로도 식도가 얼어붙는 듯합니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('녹아내린 얼음 컵', '열대야의 열기를 이기지 못하고 눈물처럼 녹아내린 얼음들. 간절했던 시원함의 기억을 품고 있습니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('수박바 막대기', '초록색 부분만 남겨두고 아껴 먹다 그만 떨어뜨린 비운의 막대기. 누군가의 절규가 들리는 듯합니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('포카리 페트병', '땀으로 빠져나간 수분을 미친 듯이 채워주던 생명수 통. 빈 페트병에서는 여전히 이온의 향이 납니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('맺힌 이슬방울', '극야의 더위를 뚫고 달리는 유저의 뺨에 맺힌, 혹은 차가운 음료 캔 겉면에 맺힌 시원한 물방울입니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('얼어붙은 생수통', '냉동실에 너무 오래 두어 돌덩이가 되어버린 생수. 이빨로 깨물어 먹으려던 처절한 이빨 자국이 보입니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('쭈쭈바 꼭지', '가위가 없어 이빨로 물어뜯다 강냉이가 털릴 뻔한 위기를 넘긴 흔적. 달콤한 즙이 아직 남아있습니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('레몬 슬라이스', '탄산음료에 띄워 상큼함을 더해주던 레몬 한 조각. 아스팔트 위에서도 상쾌한 향기를 잃지 않았습니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('바닥난 얼음틀', '여름밤의 필수품이었으나 이제는 텅 비어버린 플라스틱 틀. 내일의 러닝을 위해 다시 얼려야 합니다.', 'item', 'common', 'def1f1fe-dd44-0a0f-227b-2fb53eaa63ce', 1.0),
  ('설탕 묻은 꽈배기', '시장 골목의 인심이 듬뿍 담긴 꼬인 반죽. 한 입 베어 물 때마다 바스락거리는 설탕 소리가 예술입니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('씨앗 빠진 호떡', '가장 맛있는 씨앗 꿀 부분만 교묘하게 파먹고 버려진 겉옷. 숲속 갱단의 소행이 분명해 보입니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('윤기 나는 족발 뼈', '장충동 고수의 비법 씨육수로 삶아내 영롱한 갈색빛을 띠는 뼈다귀. 들개들이 군침을 흘리고 있습니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('찌그러진 막걸리 잔', '시끌벅적한 노포에서 누군가와 기분 좋게 부딪히며 건배를 외쳤던 흔적이 남아있는 양은 잔입니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('기름 밴 은박지', '순대 볶음이나 김밥을 따뜻하게 품어주던 은색 요람. 고소한 참기름 냄새가 코끝을 스칩니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('부러진 이쑤시개', '순대와 간을 콕콕 찍어 먹다 그만 부러져버린 얇은 나무 막대기. 미식가의 다급함이 느껴집니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('마르고 남은 순대', '떡볶이 국물에 찍어 먹을 타이밍을 놓쳐 차갑게 식어버린 순대 한 조각. 묘하게 쫀득한 매력이 있습니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('초장 묻은 비닐', '신선한 회를 포장해 가던 비닐봉지의 파편. 붉은 초장이 무심하게 묻어있어 침샘을 자극합니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('낡은 시장 바구니 조각', '검은 비닐봉지 대신 환경을 생각하던 어느 단골손님의 훈장 같은 장바구니 손잡이 파편입니다.', 'item', 'common', '91696f3a-beb7-66f3-03c0-9398596ad56e', 1.0),
  ('녹아버린 초코바', '업힐 등반 중 뒷주머니의 체온을 이기지 못하고 형태를 잃어버린 초콜릿. 포장지를 핥아먹을 수밖에 없습니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('포도당 캔디 껍질', '봉크(Bonk, 체력 고갈)가 오기 직전, 떨리는 손으로 입에 털어 넣은 기적의 하얀 알약 껍데기입니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('터진 파워젤', '단 1초의 기록 단축을 위해 다급하게 쥐어 짜내다 옷에 다 튀어버린 끈적하고 씁쓸한 화학의 맛입니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('양갱 포장지', '어르신들의 간식에서 라이더들의 최애 행동식으로 신분 상승한 팥 덩어리의 황금색 껍데기입니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('구미베어 한 마리', '주머니 속에서 탈출한 쫄깃한 곰 젤리. 아스팔트 위에서 쓸쓸하게 구조의 손길을 기다리고 있습니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('끈적이는 캬라멜', '라이딩 중 씹어 먹다 이빨에 달라붙어 호흡을 방해하던 달콤한 악마. 포장지에는 아직 단맛이 뱄습니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('콜라 빈 캔', '정상에 오르자마자 원샷으로 들이켠 생명수. 트림과 함께 모든 고통이 날아갔던 빈 캔입니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('각설탕 부스러기', '당 떨어지는 순간, 카페에 들러 커피 대신 설탕만 털어먹은 처절한 생존의 흔적입니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('마카롱 꼬끄 조각', '뷰 맛집 카페를 찾아 등반한 뒤 인증샷을 찍다 떨어뜨린 비싼 과자 부스러기. 눈물이 앞을 가립니다.', 'item', 'common', '1c3530dd-94c2-b248-8967-d0016d341ebe', 1.0),
  ('바삭한 해물파전 조각', '빗소리를 듣자마자 파블로프의 개처럼 반응하여 구워낸 전. 오징어 다리가 삐죽 튀어나와 있습니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('녹두빈대떡 부스러기', '돼지기름에 바삭하게 튀겨지듯 구워진 고소함의 극치. 빗물에 살짝 젖었지만 풍미는 살아있습니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('막걸리 앙금', '병 밑바닥에 가라앉아 있던 진득한 쌀의 흔적. 비 오는 날 아스팔트 위에 하얗게 번져 있습니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('양파 장아찌 국물', '기름진 전의 느끼함을 단숨에 씻어주던 새콤달콤한 마법의 간장. 냄새만 맡아도 침이 고입니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('젖은 종이컵', '막걸리를 듬뿍 담아 마시다 빗물에 젖어 흐물흐물해진 종이컵. 운치가 느껴지는 파편입니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('기름 튄 냅킨', '입가에 묻은 파전 기름을 닦아내고 버려진 냅킨. 빗방울을 맞아 반투명하게 변해버렸습니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('비닐우산 손잡이', '비를 피하며 전을 먹기 위해 다급하게 우산을 접다 부러뜨린 투명 비닐우산의 플라스틱 손잡이입니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('고추 썰린 간장장', '매콤한 청양고추가 동동 띄워져 있던 간장 종지의 파편. 혀끝을 알싸하게 때리던 기억이 선명합니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('막걸리병 뚜껑', '세차게 흔든 뒤 조심스럽게 탄산을 빼며 열었던 흰색 플라스틱 뚜껑. 막걸리의 짜릿함이 담겨있습니다.', 'item', 'common', 'fb3adceb-50c2-9306-ea19-8fd49637d27f', 1.0),
  ('뚝배기 파편', '용암처럼 끓어오르던 국밥을 품었던 검은 그릇의 조각. 해장 러닝의 종착지를 알리는 이정표입니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('다대기 묻은 숟가락', '맑은 국물에 붉은 양념을 신나게 풀었던 흔적. 알큰한 맛으로 위장을 씻어 내리던 도구입니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('깍두기 국물 자국', '국밥에 깍두기 국물을 부어 먹는 ''배우신 분''의 흔적. 붉은 얼룩이 테이블 위 영광의 상처처럼 남았습니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('빈 헛개수 병', '어제의 후회와 알코올을 땀으로 배출하며 갈구했던 구원의 음료. 구수한 냄새가 맴돕니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('공깃밥 뚜껑', '국밥이 나오기 전, 밥을 흔들어 동그랗게 뭉쳐놓기 위해 덮어두었던 스테인리스 뚜껑입니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('새우젓 한 마리', '돼지고기의 감칠맛을 극한으로 끌어올려 주던 작은 새우 한 마리. 아스팔트 위에서 짭짤함을 뿜어냅니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('들깨가루 뭉치', '술이 덜 깬다며 넣지 말라는 농담에도 아랑곳하지 않고 듬뿍 뿌렸던 고소한 가루들의 잔해입니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('돼지국밥 영수증', '새벽 6시, 해장 라이딩을 무사히 마쳤음을 증명하는 영수증. ''특'' 사이즈를 주문한 위대함이 돋보입니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('입 닦은 물티슈', '든든한 식사를 마치고 만족스러운 미소와 함께 입가를 훔쳐낸 시원한 박하향의 흔적입니다.', 'item', 'common', '88aecafb-04e3-5a28-68ea-396f3c632fe0', 1.0),
  ('군고구마 껍질', '영하의 밤, 검게 그을린 껍질을 벗기자 터져 나오던 황금빛 달콤함의 기억. 손가락이 까매진 흔적이 보입니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('김 모락모락 호빵', '반으로 가르는 순간 피어오르던 따뜻한 수증기. 팥이 너무 뜨거워 입천장을 데일 뻔한 위험한 간식입니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('붕어빵 봉투', '가슴속에 품고 뛰느라 눅눅해졌지만, 그 어떤 명품 백보다 소중하게 다뤄졌던 누런 종이봉투입니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('어묵 꼬치 끝동', '추위에 떨며 서서 5개나 연달아 빼먹고 남겨진 나무 꼬치. 국물에 푹 불어 부드러워져 있습니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('군밤 껍데기', '까먹기 귀찮지만 한 번 시작하면 멈출 수 없는 중독성. 다람쥐 갱단이 실수로 흘리고 간 것일지도 모릅니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('종이컵 어묵 국물', '국물 좀 더 달라는 말에 아주머니가 인심 좋게 듬뿍 퍼주신 짭짤하고 따뜻한 위로의 흔적입니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('타버린 땅콩', '밤거리 노점에서 고소한 냄새를 풍기며 구워지던 껍질 땅콩. 너무 구워져 새까맣게 타버렸습니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('호떡 꿀 묻은 장갑', '한 입 베어 무는 순간 뜨거운 설탕 꿀이 터져 나와 비싼 방한 장갑을 망쳐버린 슬픈 사연이 담겨있습니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('따뜻한 두유 병', '편의점 온장고에서 갓 꺼내 주머니에 넣고 뛰면 최고의 핫팩이 되어주는 달콤한 유리병입니다.', 'item', 'common', '99553671-7ec6-08bc-56c0-af12aa326b2b', 1.0),
  ('탄맛 나는 파닭 꼬치', '무명 트럭에서 숯불에 거칠게 구워낸 시그니처 메뉴. 파의 단맛과 닭고기의 짭짤함이 완벽한 조화를 이룹니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('염통 꼬치 막대', '쫄깃한 식감에 중독되어 10개씩 사 먹고 남겨진 얇은 나무 막대기 더미입니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('매운 데리야끼 소스', '입가에 잔뜩 묻히고 먹게 만드는 마성의 단짠 소스. 아스팔트에 떨어져 끈적한 얼룩을 남겼습니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('토치에 그을린 자국', '마지막 불맛을 입히기 위해 화려하게 불꽃을 뿜어내던 토치의 강력한 흔적이 호일에 남아있습니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('불향 나는 호일', '꼬치를 정성껏 감싸주던 은박지. 다 먹고 난 후에도 짙은 숯불 향이 배어 있어 버리기 아쉽습니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('소금 구이 파편', '양념의 화려함을 거부하고 고기 본연의 맛을 즐기는 진정한 미식가들이 흘린 짭짤한 결정체입니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('은행 꼬치 한 알', '맥주 안주로 제격인 고소하고 쌉싸름한 은행. 꼬치에서 탈출하여 데굴데굴 굴러다니고 있습니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('가스 토치 부품', '환상의 꼬치구이 트럭이 서둘러 자리를 뜨다 흘리고 간 검은색 플라스틱 점화기 부품입니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('빈 양념통', '마법의 붉은 가루가 잔뜩 들어있던 플라스틱 통. 뚜껑을 열면 매운 향에 여전히 재채기가 나옵니다.', 'item', 'common', 'bd92067a-a33a-5848-1be4-8866e503efd2', 1.0),
  ('녹슨 체인 조각', '극한의 악천후를 뚫고 달린 대가. 기름칠할 시간조차 사치였던 치열한 생존의 증거입니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('다 식어버린 핫팩', '영하의 추위 속에서 생명줄 같았던 온기의 잔해. 이제는 차갑고 딱딱한 돌덩이가 되었습니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('진흙 묻은 고어텍스 조각', '수십만 원짜리 기능성 원단도 대자연의 진흙팩 앞에서는 그저 평등한 헝겊 쪼가리일 뿐임을 증명합니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('물먹은 방수 양말', '방수의 한계를 넘어 발가락 사이로 스며든 축축함. 불쾌함마저 훈장으로 여기는 광기가 서려 있습니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('얼어붙은 물통', '수분 보충을 위해 깨물었다가 이빨이 나갈 뻔한 위기를 넘긴 흔적. 물이 아닌 빙수가 들어있습니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('흠집 난 고글 렌즈', '쏟아지는 우박과 나뭇가지를 온몸으로 막아낸 시야의 수호자. 영광의 상처가 선명하게 남아있습니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('수명이 다한 펑크 패치', '인적 없는 산속에서 타이어가 터졌을 때, 떨리는 손으로 꾹꾹 눌러 붙였던 생존 본능의 결실입니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('비바람에 꺾인 우비', '태풍과 맞서 싸우다 장렬하게 찢어져 나간 얇은 비닐. 바람의 저항을 온몸으로 느낀 잔해입니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('진흙투성이 카라비너', '무엇이든 매달 수 있는 든든한 고리지만, 지금은 진흙에 덮여 원래 색이 무엇인지조차 알 수 없습니다.', 'item', 'common', 'e9b38bc8-a2fc-9dbf-378d-d22c8f90165b', 1.0),
  ('물먹은 방수 자켓', '쏟아지는 장대비 앞에서는 ''100% 방수''라는 마케팅 문구도 무용지물이 됨을 증명하는 무거운 천입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('흙탕물 튄 고글', '앞차의 뒷바퀴에서 뿜어져 나오는 흙탕물을 정통으로 맞은 흔적. 시야 포기 선언과도 같습니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('미끄러진 타이어 자국', '젖은 노면에서 아찔하게 미끄러지며 간신히 중심을 잡은, 심장이 철렁했던 순간의 탁본입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('침수된 후미등', '빗물이 스며들어 깜빡거림을 멈춘 붉은 불빛. 오늘 밤은 당신의 생존 본능만이 유일한 안전장치입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('젖은 스마트폰 케이스', '방수폰이라 믿었지만 스피커에서 먹먹한 소리가 나기 시작할 때 찾아오는 공포가 묻어있습니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('불어터진 손가락 밴드', '빗물에 퉁퉁 불어 상처에서 떨어져 나간 밴드. 고통 따위는 빗물에 씻어 보낸 지 오래입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('녹슨 브레이크 패드', '브레이크를 잡을 때마다 칠판 긁는 소리를 내며 주변 사람들의 고막을 테러하는 쇳덩어리입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('비 내리는 날의 흙냄새', '페트리코어(Petrichor)의 진한 냄새. 폭우 속을 달린 자만이 폐부 깊숙이 들이마실 수 있는 향기입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('꺾인 우산대', '자연의 분노 앞에서 인간의 발명품이 얼마나 나약한지 보여주는 처참한 플라스틱 뼈대입니다.', 'item', 'common', '1a9035e2-eec8-2650-d0e3-e8d3558bb4e8', 1.0),
  ('얼어붙은 속눈썹', '내뱉은 거친 숨결이 그대로 눈가에 얼어붙은 흔적. 깜빡일 때마다 바스락거리는 소리가 납니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('고드름 맺힌 비니', '머리에서 뿜어져 나온 열기가 찬 공기를 만나 맺힌 영광의 얼음 기둥. 보는 것만으로도 두통이 옵니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('돌덩이 같은 핫팩', '미친 듯이 흔들어도 열기를 뱉어내지 않고 파업을 선언한, 배신감이 서린 쇳가루 주머니입니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('성에 낀 마스크', '콧물과 입김이 뒤엉켜 거대한 빙벽을 이룬 천 조각. 극한의 호흡 곤란을 유발하는 1등 공신입니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('금이 간 물통 뚜껑', '얼어붙은 뚜껑을 억지로 열려다 그만 파괴해 버린, 갈증과 괴력이 낳은 겨울철 참사입니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('동상 걸릴 뻔한 장갑', '손가락 끝의 감각이 사라지는 공포 속에서 핸들바를 부여잡았던 땀과 눈물의 결정체입니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('얼어버린 바나나', '에너지 보충을 위해 꺼냈으나 호신용 무기로 써도 될 만큼 단단해진 둔기형 과일입니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('방한화 밑창 조각', '빙판길을 밟다 뜯어져 나간 고무 조각. 미끄러짐을 방지하려다 본인이 미끄러진 비운의 파편입니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('차디찬 북서풍의 조각', '살을 에는 듯한 칼바람을 병에 담았습니다. 뚜껑을 열면 뺨을 찌르는 듯한 한기가 퍼집니다.', 'item', 'common', 'e14da4c2-53c0-37c1-8816-3ec48a0dcd23', 1.0),
  ('진흙 덮인 클릿 슈즈', '페달에 끼워지지 않아 탕탕 치며 분노를 표출하게 만든 덩어리. 신발의 원형을 잃었습니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('풀잎 엉킨 스프라켓', '오프로드를 거칠게 누빈 대가로 구동계에 샐러드가 차려진 기괴하고도 자연 친화적인 풍경입니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('나뭇가지 꽂힌 헬멧', '수풀을 뚫고 지나가다 강제로 얻게 된 친환경 안테나. 야생의 위장술로 완벽한 아이템입니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('흙투성이 무릎 보호대', '자갈밭을 구르고 넘어져도 무릎의 슬개골을 굳건히 지켜준 든든하고 더러운 방패입니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('마른 진흙 가루', '며칠 전의 영광을 잊지 못하고 현관에 우수수 떨어져 등짝 스매싱을 유발하는 흙먼지입니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('야생 동물의 털', '풀숲을 헤치다 우연히 마찰을 일으킨 짐승의 흔적. 곰인지 고라니인지 알 수 없어 서늘해집니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('긁힌 프레임 도장', '새 자전거에 난 첫 스크래치의 아픔. 하지만 이들은 이를 ''영광의 상처''라 부르며 정신 승리합니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('세차장 동전 뭉치', '이 모든 진흙을 고압수로 날려버리기 위해 주머니에서 짤랑거리는 묵직한 희망입니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('흙 맛 나는 땀방울', '앞사람이 튀긴 흙탕물이 입으로 들어왔을 때, 뱉지 않고 쿨하게 삼켜버린 야생의 짭짤함입니다.', 'item', 'common', '7ba44a13-fece-0409-75c4-5a36676c1fdf', 1.0),
  ('방전된 헤드랜턴', '칠흑 같은 산속에서 불이 꺼지는 순간의 공포를 머금은 껍데기. 여분 배터리를 안 챙긴 대가입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('부러진 등산 스틱', '체중을 온전히 지탱하다 비명을 지르며 꺾여버린 카본 막대. 이제는 땔감으로나 쓸 수 있습니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('야광 반사 띠', '헤드라이트 불빛에 번쩍이며 서로의 생존을 확인시켜 주던 생명줄. 달빛 아래서 은은하게 빛납니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('놀라 도망친 고라니 털', '정적을 찢는 고라니의 기괴한 비명에 심장이 멎을 뻔했던 그 야심한 밤의 기억입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('반쯤 먹은 비상식량', '체력 고갈의 위기에서 덜덜 떨리는 손으로 씹어 먹다 턱이 아파 남긴 초코바 조각입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('이슬 맺힌 나뭇잎', '새벽안개를 머금은 서늘한 잎사귀. 바스락거리는 발소리를 죽여주는 산속의 훌륭한 카페트입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('산모기 퇴치제', '독한 향기에도 아랑곳하지 않고 레깅스를 뚫고 침을 꽂는 전투 모기들과의 치열했던 화학전 잔해입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('비상용 호루라기', '길을 잃었을 때 불기 위해 챙겼으나, 다행히 한 번도 입술을 대지 않은 안도의 플라스틱입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('별빛 한 조각', '가로등 하나 없는 능선에 누워 바라본 쏟아지는 은하수. 도시에서는 절대 주울 수 없는 조각입니다.', 'item', 'common', '102322b0-8735-86a1-5eb6-b0423f116e42', 1.0),
  ('끊어진 변속 와이어', '업힐에서 댄싱을 치는 순간 ''툭'' 하는 소리와 함께 허벅지 근육을 파괴한 배신자입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('수명 다한 타이어 튜브', '펑크 패치만 5개가 붙어 있어 더 이상 공기를 품을 수 없는 걸레짝이 된 고무 링입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('휘어진 크랭크 암', '얼마나 무식한 파워로 밟아댔는지 쇳덩이가 엿가락처럼 휘어버린, 광기의 증명서입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('터진 에어 쿠션', '푹신함을 제공하던 운동화의 에어가 터지며 ''픽'' 소리를 내고 사망한, 발바닥의 비극입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('찍힌 스마트워치 액정', '바위에 긁혀 거미줄처럼 금이 간 액정. 심박수는 정상이나 수리비 생각에 심장이 요동칩니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('찢어진 압박 타이즈', '나뭇가지에 걸려 속살을 강제로 드러내게 된, 기능성을 완전히 상실한 쫀쫀한 천 쪼가리입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('나사 빠진 선글라스', '덜컹거리는 다운힐에서 나사 하나를 흘려 렌즈가 달랑거리는 비운의 고글 파편입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('마모된 클릿', '계단을 오르내리다 닳고 닳아 더 이상 페달과 결합되지 않는 플라스틱. 펭귄 걸음의 원인입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('기름때 묻은 정비 장갑', '길거리에서 체인이 빠졌을 때, 손을 더럽히지 않기 위해 장렬히 희생된 시커먼 면장갑입니다.', 'item', 'common', '06f0dba2-805b-4631-8a3f-4111fa88db7c', 1.0),
  ('녹아내린 신발 밑창', '섭씨 40도로 끓어오르는 아스팔트 위를 달리다 끈적하게 눌어붙어 버린 고무의 눈물입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('끓어오르는 물통', '보냉 물통조차 이기지 못한 지열. 한 모금 마시는 순간 식도가 데일 뻔한 미온수 폭탄입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('화상 입은 팔 토시', '자외선을 막으려 꼈으나 오히려 찜질기가 되어버린, 땀에 전 축축한 쿨토시입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('증발해 버린 땀방울', '맺히자마자 열기에 말라붙어 피부에 소금 결정을 남긴 짜디짠 한여름의 훈장입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('변형된 플라스틱 캡', '뜨거운 햇살 아래 방치되었다가 찌그러져 다시는 원래 모양으로 돌아오지 않는 불쌍한 뚜껑입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('뜨거운 아스팔트 조각', '운동화 밑창에 박혀 집 안까지 따라 들어온, 열기를 가득 머금은 까만 돌멩이입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('바짝 마른 목캔디', '더위를 식히기 위해 입에 넣었으나 침마저 말라버려 목구멍을 턱 막히게 한 건조한 사탕입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('아지랑이의 환영', '오르막길 끝에 오아시스가 보인다고 믿게 만든, 뇌가 열에 익어버린 순간의 환각입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('자외선 차단제 빈 통', '미친 듯이 덧발라 하얀 가부키 화장이 되었지만 결국 새카맣게 타버린 슬픈 현실의 증거입니다.', 'item', 'common', 'bc33de8f-7f87-ee74-1680-c0a09008a04a', 1.0),
  ('피 묻은 반창고', '자전거에서 넘어지거나 돌부리에 채인 후, 급하게 편의점에서 사 붙인 눈물겨운 응급처치입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('구겨진 파스 껍질', '허벅지와 종아리에서 불타오르는 근육통을 잠재우기 위해 뜯어낸 파스의 서늘한 잔해입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('소독약 냄새나는 거즈', '빨간약을 듬뿍 바른 뒤 덧대어, 지나갈 때마다 병원 냄새를 풍기게 만드는 아픈 천 조각입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('까진 무릎 딱지', '샤워할 때마다 비명을 지르게 만드는 쓰라린 상처. 떼어내고 싶은 충동을 간신히 참아야 합니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('찢어진 바지 무릎', '아끼던 고가의 아웃도어 바지가 아스팔트와 키스하며 남긴 통장 잔고의 뼈아픈 출혈입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('스프레이 파스 빈 통', '뿌릴 때만 잠시 시원하고 이내 통증이 밀려오지만, 플라시보 효과를 위해 다 써버린 깡통입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('부러진 손톱', '넘어지며 땅을 짚다 그만 날아가 버린 손톱. 키보드를 칠 때마다 그날의 아픔이 떠오릅니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('멍든 자국', '며칠 전 어딘가에 부딪혔는지 기억도 안 나지만, 허벅지에 선명하게 남아있는 보랏빛 훈장입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('이 악문 치아 자국', '한계를 돌파할 때 뿜어내는 괴력. 마우스피스라도 껴야 할 만큼 꽉 깨문 고통의 흔적입니다.', 'item', 'common', '7a3b59a7-2cca-f2c2-11bd-73e73564087c', 1.0),
  ('유통기한 지난 건빵', '배낭 구석에 박아두고 까맣게 잊고 있다가, 허기에 지쳐 꺼내 씹은 퍼석한 밀가루 블럭입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('구겨진 은박 보온 담요', '저체온증의 위기에서 바스락거리며 몸을 감쌌던, 가장 얇고 가장 위대한 생명 구명조끼입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('다 쓴 정수 알약', '계곡물을 떠 마셔야 했던 절박한 순간, 배탈의 공포를 이겨내기 위해 투하한 화학약품 빈 통입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('먼지 쌓인 나침반', '스마트폰 배터리가 꺼진 후, 떨리는 손으로 꺼내 북쪽을 찾던 아날로그 생존의 길잡이입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('마지막 성냥개비', '젖은 손으로 긋다 수차례 실패하고 간신히 불씨를 피워낸, 기적의 빨간 머리 막대기입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('비상금 만원 지폐', '배낭 가장 깊숙한 곳 지퍼백에 꼬깃꼬깃 숨겨둔, 정 안되면 택시를 부를 수 있다는 최후의 안도감입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('닳아버린 구급상자', '대일밴드와 연고는 모두 사라지고 정체 모를 알약만 굴러다니는 생존 배낭 속 빨간 파우치입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('바스라진 육포', '형태를 잃고 가루가 되어버렸지만 짭짤한 고기 맛으로 엔돌핀을 돌게 한 훌륭한 비상식량입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('살아남았다는 안도감', '무사히 집 현관문을 열고 들어왔을 때, 무거운 배낭을 내던지며 내뱉은 깊고 진한 한숨입니다.', 'item', 'common', 'b8d5d84e-9819-02f8-d302-15b7cccac325', 1.0),
  ('날아간 모자 챙', '강풍에 속수무책으로 뜯겨 날아가버려, 빗속에서 시야 확보를 포기하게 만든 모자의 잔해입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('뒤집힌 우산 살대', '비바람을 막으려 펼쳤으나 1초 만에 뒤집어져 위성 안테나가 되어버린 처참한 흉물입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('강풍에 찢긴 깃발', '교량 위에 걸려있던 깃발이 폭풍우를 견디지 못하고 찢겨 날아와 얼굴을 강타한 조각입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('바람에 날아온 신문지', '시야가 가려진 찰나, 축축한 신문지가 헬멧에 달라붙어 시야를 100% 차단한 공포의 순간입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('짠 내 나는 비구름', '해안가에서 몰아친 태풍이 바닷물을 머금고 내륙으로 쏟아낸, 입술에 닿은 짭짤한 빗물의 파편입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('꺾인 나뭇가지', '길바닥을 나뒹굴며 휠셋에 끼일 뻔한 지뢰. 자연이 아스팔트 레인저에게 던지는 묵직한 경고장입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('태풍 경보 재난문자', '삐익- 거리는 굉음과 함께 울리며, 방구석에 있어야 할 자신이 왜 여깄는지 후회하게 만듭니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('돌풍의 파동', '자전거째로 옆으로 밀려나게 만드는 무자비한 측풍. 뼈저리게 느낀 자연의 거대한 힘입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('고요한 태풍의 눈', '폭풍우가 쏟아지다 거짓말처럼 멈춘 찰나의 순간. 하늘이 열린 듯한 기괴한 평화로움입니다.', 'item', 'common', 'a44e3e21-9b4b-ba10-130e-3fb6b270702d', 1.0),
  ('훔쳐간 핫도그 소시지', '낭만 미식가의 핫도그에서 소시지만 정교하게 빼간 예술적인 절도 범죄의 증거물입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('고양이의 젤리 발자국', '은밀하게 다가와 가방을 털고 간 도둑의 귀엽고도 치명적인 분홍빛 지문입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('반짝이는 도토리', '그루터기 살롱에서 통용되는 최고급 화폐. 인간의 돈으로는 절대 환전할 수 없습니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('새가 쪼아먹은 사과', '가장 달콤한 부분만 정확히 노려 쪼아 먹은, 날개 달린 미식가들의 흔적입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('찢어진 에너지 바 봉지', '등산객의 가방 지퍼를 열고 내용물만 쏙 빼간 다람쥐 갱단의 대담한 범행 현장입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('다람쥐의 숨겨둔 호두', '어딘가에 묻어두고 정작 본인도 까맣게 잊어버려, 결국 당신의 인벤토리에 들어온 견과류입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('길고양이의 털뭉치', '알레르기가 있는 사람에게는 치명적인 생화학 무기. 바람을 타고 굴러다닙니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('빼앗긴 츄르 껍질', '자발적인 헌납이 아니라, 날카로운 발톱에 위협당해 강제로 상납하고 남은 빈 껍데기입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('부러진 까치의 깃털', '반짝이는 물건을 훔치려다 들켜 황급히 도망치다 흘린 흑백의 단서입니다.', 'item', 'common', '68a6ef7d-8ef3-117b-b25c-1418e1c5d416', 1.0),
  ('부스러진 새우깡', '비둘기 마피아들에게 상납하기 위해 공원 벤치에 뿌려진 짭짤한 밀가루 뇌물입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('쪼아먹은 샌드위치', '잠깐 벤치에 두고 한눈판 사이, 참새 특공대가 정확히 햄과 치즈만 파먹은 참사입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('비둘기의 회색 깃털', '도심의 진정한 지배자, ''닭둘기'' 보스가 날갯짓 한 번으로 남기고 간 묵직한 위엄입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('참새의 작은 발자국', '귀여운 외모로 방심을 유도한 뒤 크루아상을 털어가는 짹짹이 갱단의 스텝 자국입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('공원 벤치 나뭇조각', '비둘기들의 회의 장소로 쓰이는 벤치. 무수한 부리 공격에 파여 나간 흔적이 역력합니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('쏟아진 팝콘', '주말 공원에서 아이가 넘어지며 쏟은 순간, 수십 마리의 비둘기가 몰려든 공포의 현장 잔해입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('빼앗긴 감자튀김', '야외 햄버거의 여유를 즐기다 까치에게 공중 강탈당한, 짭짤하고 바삭한 패배의 기억입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('주인 잃은 돗자리 조각', '개미 떼와 비둘기들의 맹공에 버티지 못하고 결국 인간이 포기하고 도망친 영토입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('승리의 날갯짓', '인간의 점심을 성공적으로 털고 날아오를 때 발생하는 건방지고도 경쾌한 파동입니다.', 'item', 'common', '27249944-6e0c-081a-6df2-8b5fd57d31df', 1.0),
  ('뜯어진 종량제 봉투', '밤의 제왕들이 날카로운 발톱으로 완벽하게 절개하여 내용물을 검열한 흔적입니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('깨끗하게 핥은 참치캔', '설거지가 필요 없을 정도로 완벽하게 잔여물을 제거한, 길고양이 보스의 만찬 그릇입니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('서열 1위의 털 뭉치', '골목길 치열한 영역 다툼에서 승리한 대장의 위풍당당한 전리품. 만지면 하악질 소리가 들릴 듯합니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('할퀸 벽돌 자국', '자신의 구역임을 선포하며 발톱을 갈아낸 흔적. 골목길 마피아들의 살벌한 경고장입니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('생선 가시 뼈', '어디서 구했는지 알 수 없는 신선한 조기 한 마리를 뼈와 살로 완벽히 분리한 발골의 예술입니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('버려진 츄르 비닐', '츄르를 다 짜주지 않고 손가락에 묻혀 약올리던 인간을 응징하고 빼앗은 승리의 전리품입니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('경계하는 눈빛', '어둠 속에서 헤드라이트에 반사되어 번쩍이는 두 개의 눈동자. 심장을 철렁하게 만듭니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('담벼락의 이끼', '고양이 마피아들의 은밀한 이동 경로. 발소리를 흡수해 주는 천연 카펫 역할을 합니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('길고양이의 하악질 소리', '구역을 침범한 자에게 보내는 털 세운 경고. 이 소리를 들었다면 당장 뒤돌아가는 게 좋습니다.', 'item', 'common', '93a53906-a042-cff2-77de-0a3ca8da5eae', 1.0),
  ('볼따구에 숨긴 도토리', '볼이 터질 듯 쑤셔 넣었던 도토리 중 입 밖으로 툭 떨어져 버린 안타까운 한 알입니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('껍질 벗긴 밤송이', '가시를 피해 교묘하게 알맹이만 파낸 흔적. 다람쥐 조직원들의 정교한 기술력을 보여줍니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('노란 은행잎 코팅', '추운 겨울 식량 창고를 위장하기 위해 정성스럽게 덮어둔 친환경 노란색 위장막입니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('다람쥐의 이빨 자국', '단단한 호두껍데기에 남겨진 맹렬한 설치류의 흔적. 손가락을 조심해야 할 것 같습니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('낙엽 더미 조각', '식량을 숨기기 위해 미친 듯이 파헤치고 덮었던 다람쥐의 다급한 손길이 느껴집니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('잣송이 껍질', '솔방울 갱단과의 치열한 영역 다툼 끝에 쟁취한 고소한 잣의 껍데기 잔해입니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('파묻은 흙먼지', '아무도 모르게 보물을 숨기려 했으나, 흙을 파내다 실수로 남긴 치명적인 단서입니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('겨울눈 가지', '추운 겨울을 버티기 위한 다람쥐의 최후의 비상식량. 쌉싸름한 맛이 납니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('포동포동한 꼬리털', '월동 준비를 마쳐 한껏 살이 오른 다람쥐가 나무를 타다 나뭇가지에 걸리고 간 털 뭉치입니다.', 'item', 'common', '0ee39bb4-b882-1524-49fe-18879115d396', 1.0),
  ('구겨진 은박지', '초콜릿 껍질이지만 햇빛에 반사된다는 이유만으로 까치 도둑의 타깃이 된 쓰레기입니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('반짝이는 병뚜껑', '맥주병 뚜껑. 둥지 인테리어의 화룡점정을 장식하기 위해 까치가 물고 가던 보물입니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('누군가의 잃어버린 동전', '자판기 아래 떨어져 있던 500원짜리 동전. 까치 둥지 은행에 저축될 뻔했습니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('깨진 유리구슬', '아이들의 놀이터에서 강탈해 간 영롱한 구슬. 빛을 반사하며 까치의 눈을 멀게 했습니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('은색 옷핀', '둥지 보수 공사에 쓰기 위해 인간의 빨래 건조대에서 은밀하게 빼돌린 뾰족한 도구입니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('까치의 흑백 깃털', '절도 현장에 당당하게 남겨두고 간 시그니처 마크. 잡을 테면 잡아보라는 조롱이 담겨있습니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('둥지의 마른 나뭇가지', '인간의 옷걸이, 철사, 머리카락과 함께 정교하게 엮여있던 최첨단 조류 건축물의 파편입니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('알루미늄 캔 조각', '도로에 굴러다니던 캔 쪼가리. 눈부신 은빛 겉면 덕분에 숲속 갱단 최고급 장신구로 취급받습니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('철조망 파편', '안전을 위해 둘러놓은 철조망마저 둥지 재료로 써버리는 까치의 무시무시한 건축 본능입니다.', 'item', 'common', '1407bbea-f57a-aa97-2dce-c6ec834bec1c', 1.0),
  ('끊어진 낡은 목줄', '한때 인간의 가족이었으나 이제는 야성의 지배자가 된 들개의 슬프고도 위협적인 상징입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('거친 진흙 발자국', '잘 포장된 공원 산책로를 가로지르는, 거칠고 일정한 야생의 보폭이 담긴 진흙 탁본입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('이빨 자국 난 원반', '누군가 공원에서 반려견과 놀다 잃어버린 원반. 밤사이 들개 무리의 장난감이 되었습니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('들개의 거친 숨소리', '적막한 야간 러닝 중 등 뒤에서 들려와 심장을 멎게 만드는 낮고 그르렁거리는 소리입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('수풀에 걸린 털', '사냥감을 쫓아 가시덤불을 거침없이 돌파하며 남긴, 거칠고 뻣뻣한 야생의 털 뭉치입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('버려진 개껌', '야생의 고기를 맛본 자에게 가죽으로 만든 가짜 뼈다귀는 그저 플라스틱 쓰레기일 뿐입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('야생화 줄기', '사냥을 위한 은신처를 만들기 위해 짓밟히고 꺾여버린 불쌍한 들꽃의 파편입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('경고 표지판 조각', '들개 출몰 주의''라고 적힌 팻말을 날카로운 이빨로 물어뜯어 경고를 비웃은 흔적입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('달빛 아래 하울링', '자정 무렵, 동료들을 부르기 위해 산등성이에서 뿜어내는 소름 돋게 구슬픈 울음소리입니다.', 'item', 'common', '1d5c6b3a-8498-71bb-a1db-87b02032013e', 1.0),
  ('벌집 조각', '등산로 한가운데 거대한 왕국을 건설하려다 119 구조대원에게 강제 철거당한 육각의 잔해입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('너구리의 도둑 가면 털', '쓰레기통을 뒤지다 눈이 마주친 순간, 뻔뻔하게 너구리 라면을 연상시키는 가면을 쓴 얼굴 털입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('파헤쳐진 쓰레기통', '간밤에 너구리 갱단이 벌인 성대한 뷔페 파티의 참혹한 현장. 냄새가 코를 찌릅니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('과일 껍질 무덤', '주말 등산객들이 버리고 간 사과와 배 껍질만 알뜰하게 골라 먹은 야생동물들의 짬처리 흔적입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('말벌의 독침', '경고 비행을 무시하고 다가간 자에게 꽂히는 숲속 갱단 최고 살상 무기의 파편입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('놀란 시민의 영수증', '산책로에 갑자기 튀어나온 고라니에 놀라 커피를 엎지르며 떨어뜨린, 비명이 들리는 영수증입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('경고 테이프 조각', '뱀 출몰 지역을 알리려 둘러놓았으나, 정작 동물들은 아무렇지 않게 끊고 지나간 무용지물입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('부러진 나무 팻말', '야생 멧돼지가 등 긁개로 사용하다 그만 박살 내버린 국립공원 안내 표지판의 잔해입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('꿀벌의 구조요청', '말벌 마피아의 습격으로 쑥대밭이 된 벌집에서 도망쳐 나온 일벌의 다급한 날갯짓 파동입니다.', 'item', 'common', '876f9690-6308-5dca-5bea-4c197dade0cd', 1.0),
  ('반딧불이의 희미한 빛', '오염되지 않은 깊은 숲속, 밤의 무도회를 밝히기 위해 켜진 천연 네온사인 불빛입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('나방의 인분 가루', '가로등을 클러치 삼아 미친 듯이 춤추다 흩날린, 피부에 닿으면 가려운 미세한 가루입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('귀뚜라미의 날개 톱니', '가을밤 무도회의 백그라운드 뮤직을 연주하기 위해 닳고 닳은 현악기의 부품입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('달빛 젖은 거미줄', '벌레들을 춤판으로 유인하기 위해 이슬을 머금고 화려하게 위장한 끈적이는 함정입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('버섯 포자 가루', '습기 찬 밤, 숲의 정령들이 환각 파티를 벌일 때 공기 중으로 뿜어내는 몽환적인 연기입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('이슬 맺힌 클로버', '밤의 무도회장에 입장하는 작은 곤충들에게 제공되는 신선하고 시원한 웰컴 드링크입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('부러진 풀잎 지휘봉', '여름밤 풀벌레 교향악단을 지휘하던 사마귀 마에스트로가 열정을 이기지 못하고 꺾어버린 풀잎입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('매미 허물', '치열했던 여름의 노래를 끝내고, 무도회장 한구석에 덩그러니 남겨둔 반투명한 드레스입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('밤안개 조각', '숲의 정령들이 은밀한 무도회를 인간의 눈으로부터 숨기기 위해 깔아둔 마법의 연막탄입니다.', 'item', 'common', '6fc07713-c620-5fe8-dac1-475de83976d2', 1.0),
  ('황금빛 도토리', '일반 도토리 1,000개의 가치를 지닌다는 전설의 화폐. 살롱 VIP룸에 입장할 수 있는 티켓입니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('최고급 캣닢 뭉치', '길고양이 보스들을 단숨에 무장해제시키고 배를 뒤집게 만드는 마약 같은 향기의 허브 뭉치입니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('다이아몬드 큐빅', '어느 사모님의 구두에서 떨어져 나와 까치 도둑의 부리를 거쳐 살롱의 최고가 매물로 둔갑한 큐빅입니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('잃어버린 결혼반지', '등산 중 계곡에서 손을 씻다 빠진 반지. 다람쥐가 물고 가 살롱의 샹들리에 장식으로 쓰이고 있습니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('스마트키 조각', '공원 잔디밭에 떨어뜨린 차 키. 까마귀가 주워 살롱의 금고 열쇠로 용도 변경되었습니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('명품 가방의 지퍼', '야외 테라스에서 밥을 먹다 길고양이에게 테러당한 G사 가방의 뜯겨나간 슬픈 부품입니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('보스의 발톱 자국', '살롱의 질서를 어지럽힌 자에게 남겨지는 무시무시한 징벌의 흔적. 3줄의 흉터가 선명합니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('살롱의 VIP 출입증', '오직 10년 이상 숲을 지배한 동물 마피아 간부들만 지닐 수 있다는, 향나무 껍질로 만든 패스입니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('은밀한 거래 장부', '훔쳐 온 인간의 식량과 숲의 보물들이 교환된 내역이 진흙과 발자국으로 빼곡히 기록된 나뭇잎입니다.', 'item', 'common', '3a7f3fa1-08de-ad46-8c03-ac0ada645054', 1.0),
  ('마른 짚단 뭉치', '찬 바람을 막기 위해 숲의 갱단들이 온 동네를 털어 모아 만든 포근한 침대의 재료입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('동면 동굴의 흙', '겨울이 오기 전, 아무도 찾지 못하게 입구를 막아버린 은밀하고 따뜻한 지하 벙커의 흙먼지입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('포근한 솜털', '깊은 잠에 빠진 동물의 숨결에 맞춰 부풀어 오르는, 세상에서 가장 따뜻한 천연 난방재입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('새근거리는 숨소리', '얼어붙은 땅 아래, 봄이 오기만을 기다리며 느리게 뛰는 심장과 고요한 생명의 리듬입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('얼어붙은 낙엽', '동면 동굴 위를 덮어 차가운 눈을 막아주는, 바스락거리는 천연 단열재 껍데기입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('마지막 남은 식량', '동면 도중 잠시 깼을 때 먹기 위해 가장 가까운 곳에 숨겨둔 말라비틀어진 열매입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('솔잎 이불', '뾰족하지만 신기하게도 몸을 웅크리면 체온을 완벽하게 가둬주는 마법의 숲속 이불입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('동면을 알리는 첫눈', '이제 모든 범죄 활동을 멈추고 땅속으로 들어가야 함을 알리는 숲속 갱단의 통금 사이렌입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('봄을 기다리는 씨앗', '다람쥐가 숨겨놓고 자버린 탓에, 결국 봄이 되면 싹을 틔울 운명을 가진 생명의 파편입니다.', 'item', 'common', '75cb518f-77c2-b1af-4d11-e0843c7517e5', 1.0),
  ('잃어버린 렌즈 캡', '노을이 지는 찰나의 순간을 놓치지 않기 위해 다급하게 렌즈를 열다 한강 다리 밑으로 굴러간 비운의 뚜껑입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('반쯤 마신 아아', '완벽한 타임랩스를 찍기 위해 1시간째 다리 위에 서 있다가 얼음이 다 녹아 밍밍해진 생명수입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('노을빛 필름 조각', '단 15분만 허락되는 붉고 보랏빛의 영롱한 하늘을 아날로그 감성으로 담아낸 작은 파편입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('스마트폰 삼각대 마운트', '강풍을 이기지 못하고 삼각대가 쓰러지며 장렬하게 전사한 플라스틱 연결 부품입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('빨간 셀로판지', '디지털 필터를 거부하고 카메라 렌즈 앞에 직접 대어 아날로그 붉은빛을 연출하던 고전적인 도구입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('해질녘의 그림자', '길게 늘어지는 그림자를 이용해 감성적인 인증샷을 찍을 때 발생하는 몽환적인 흑백의 파동입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('카메라 스트랩 조각', '위험한 난간에 매달려 셔터를 누르다 긁히고 뜯겨 나간 두꺼운 나일론 줄의 파편입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('다 쓴 필름통', '36장의 컷에 오늘 하루의 가장 아름다운 빛을 모두 가둬버리고 남은 가벼운 플라스틱 빈 껍데기입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('빛 번짐 필터', '야간 노을의 빛 갈라짐을 극대화하기 위해 렌즈에 끼워 넣었던, 지문이 잔뜩 묻은 유리 조각입니다.', 'item', 'common', 'ad1a2ef7-4499-0773-f0c8-ba31e96087f2', 1.0),
  ('녹아버린 아포가토', '아이스크림이 녹기 전 사진을 찍어야 한다는 압박감 속에 수백 장의 셔터를 누르다 결국 커피 물이 되어버린 디저트입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('예쁜 카페 냅킨', '단순한 휴지가 아닙니다. 감성적인 로고가 박혀 있어 컵 아래 무심하게 깔아둬야 하는 필수 소품입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('스탬프 쿠폰', '깊은 산속 뷰 맛집을 10번이나 방문했다는 증표. 그러나 다 모으기도 전에 카페가 폐업해 버린 슬픈 종이 쪼가리입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('에스프레소 잔 파편', '테라스석의 완벽한 구도를 잡기 위해 이리저리 옮기다 그만 바닥에 떨어뜨려 산산조각 난 씁쓸한 잔해입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('원두 찌꺼기', '카페 뒷마당에 버려진, 진한 커피 향이 배어 있어 방향제로 쓰겠다고 주워 온 촉촉한 가루들입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('카페 진동벨', '사진 찍기에 정신이 팔려 메뉴가 나온 줄도 모르고 주머니에 넣은 채 산을 내려와 버린 절도의 증거물입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('시럽 묻은 빨대', '달콤한 에이드를 휘휘 젓다 감성샷을 위해 급하게 빼내어 테이블에 얼룩을 남긴 주범입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('디저트 포크', '케이크를 먹기 위한 도구가 아니라, 예쁜 단면을 보여주기 위해 살짝 떠서 멈춰 있어야 하는 촬영용 소품입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('포토존 입장권', '음료 값보다 뷰 값이 더 비싼 식물원 카페에서, 오직 이 한 장의 사진을 위해 기꺼이 결제한 바코드 영수증입니다.', 'item', 'common', '9a9a6ffb-c2dd-2e8c-98f0-e133bf05d99e', 1.0),
  ('이슬 맺힌 렌즈 닦이', '새벽 4시의 엄청난 습기를 이기지 못하고 축축하게 젖어버려 더 이상 렌즈를 닦을 수 없는 무용지물 천입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('물기 먹은 모자', '밤새 산안개를 정통으로 맞아 묵직해진 캡 모자. 챙 끝에서 물방울이 뚝뚝 떨어집니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('김서림 방지제', '카메라 렌즈에 김이 서리는 것을 막기 위해 미친 듯이 뿌려댄 화학약품 빈 통입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('새벽이슬의 조각', '거미줄에 매달린 영롱한 이슬방울에 매크로 렌즈를 들이대다 옷깃으로 건드려 떨어뜨린 차가운 물방울입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('방수 카메라 케이스', '호숫가 물안개를 찍다 미끄러져 장비가 물에 빠질 뻔한 아찔한 순간을 막아준 생명의 은인입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('모기향 잿가루', '여름 새벽의 전투 모기 떼로부터 피 같은 피를 지켜내기 위해 밤새 피워둔 나선형 향의 허무한 잔해입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('헤드랜턴 건전지', '포인트를 찾아 어둠 속을 헤매다 수명을 다해버려 셔터 마피아를 칠흑 속에 갇히게 한 배신자입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('젖은 나뭇가지', '전경을 가리는 나뭇가지를 살짝 치우려다 잎에 맺힌 물폭탄을 뒤집어쓰게 만든 덫입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('몽환의 필터', '안개 낀 풍경을 더욱 비현실적으로 만들어주지만, 사실 렌즈에 입김을 불어 만든 천연 소프트 필터의 흔적입니다.', 'item', 'common', '436bb10f-68c3-4846-158b-fc7d3a62e674', 1.0),
  ('LED 라이트 조각', '피사체의 얼굴에 드라마틱한 빛을 주려다 떨어뜨려 패널이 박살 난, 눈부신 슬픔의 잔해입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('삼각대 고무발', '육교 위 거친 아스팔트와 사투를 벌이다 결국 닳고 뜯어져 나간 하체의 일부분입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('네온사인 유리조각', '사이버펑크 감성을 담겠다며 골목길을 쏘다니다 발견한, 아직 미세한 전류가 흐르는 붉은 유리 파편입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('장노출 릴리즈 선', '카메라의 흔들림을 막기 위해 길게 연결했던 선. 어둠 속에서 발에 걸려 대형 참사를 일으킬 뻔했습니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('핫팩 껍질', '야경 촬영의 가장 큰 적, 수족냉증과 싸우며 손가락 감각을 살려내기 위해 뜯어낸 은박 포장지입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('보조배터리 케이블', '영하의 날씨에 급격히 방전되는 스마트폰에 생명을 불어넣기 위해 주렁주렁 매달고 다니던 탯줄입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('편의점 캔커피 뚜껑', '칼바람 부는 육교 위에서 타임랩스가 끝나기를 기다리며 덜덜 떨리는 손으로 홀짝인 따뜻한 라떼의 흔적입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('빛의 궤적 파편', '장노출로 담아낸 붉은 테일램프의 선. 사진 속에서 튀어나와 허공에 아른거리는 묘한 시각적 잔상입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('차량 헤드라이트 빛', '어둠 속에서 카메라 렌즈를 정통으로 때려 기껏 찍던 장노출 사진을 하얗게 날려버린 분노의 빛 덩어리입니다.', 'item', 'common', 'd094bab5-0ca9-2200-f188-424be9a00b47', 1.0),
  ('녹슨 철조망 파편', '관계자 외 출입금지'' 표지판을 기어코 넘어가다 아끼던 바지를 찢어먹은 날카로운 쇳조각입니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('부서진 벽돌 조각', '빈티지한 감성의 최고봉이라 불리는 붉은 벽돌. 발을 헛디뎌 먼지를 일으키며 셔터 찬스를 망쳤습니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('마른 잡초 무더기', '폐공장 마당에 무성하게 자란 잡초. 쓸쓸한 분위기를 연출하려 일부러 꺾어 카메라 앞에 배치한 소품입니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('경고문 팻말 조각', '접근하지 말라는 경고마저 인더스트리얼 감성의 완벽한 피사체로 승화시킨 마피아들의 대담함이 묻어있습니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('먼지 쌓인 필터', '폐건물 특유의 퀴퀴한 먼지를 정통으로 뒤집어써, 닦아도 닦아도 뿌연 화면을 만들어내는 렌즈 필터입니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('거미줄 엉킨 후드', '렌즈 보호용 후드에 대왕 거미집이 걸려, 사진을 찍는 내내 렌즈 앞에 거미가 기어 다니는 공포를 선사했습니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('폐공장의 자물쇠', '묵직하고 녹슨 철제 자물쇠. 그 자체로 시간의 흐름을 보여주는 완벽한 오브제지만 열쇠는 어디에도 없습니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('버려진 작업장갑', '수십 년 전 누군가의 피땀이 서린, 흙먼지가 단단하게 굳어 마치 박제된 손처럼 보이는 기괴한 목장갑입니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('스산한 바람소리', '깨진 유리창 틈으로 들어오는 소름 돋는 바람 소리. 폐허의 분위기를 압도하며 등골을 서늘하게 만듭니다.', 'item', 'common', '7f745d9d-0f5f-23da-c024-aeaa94af139e', 1.0),
  ('떨어진 벚꽃잎', '꽃비가 내리는 완벽한 타이밍을 포착하려다 렌즈 뷰파인더에 딱 붙어버린 눈치 없는 분홍빛 꽃잎입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('분홍색 필터', '흐린 날씨에도 무조건 봄날의 화사함을 연출하겠다는 의지로 렌즈 앞에 끼워둔 마법의 색안경입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('구겨진 돗자리 조각', '좋은 앵글을 잡겠다고 인파 속을 헤집다 누군가의 피크닉 매트를 밟고 지나간 치열한 자리싸움의 흔적입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('도시락통 뚜껑', '꽃구경을 빙자한 출사에서 허기를 달래려 싸온 김밥을 급하게 먹다 날려버린 일회용 플라스틱 뚜껑입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('셀카봉 부품', '수백 명의 상반신 위로 카메라를 치켜들다 인파에 치여 똑 부러져버린 알루미늄 막대기 잔해입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('선글라스 파편', '눈부신 봄 햇살을 피하려다 나뭇가지에 걸려 바닥에 떨어져 금이 간 슬픈 렌즈 조각입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('블루투스 리모컨', '자연스러운 전신 샷을 찍으려 손에 쥐고 몰래 누르다 결국 풀숲 어딘가에 잃어버린 작고 까만 버튼입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('벌에 쏘인 연고', '꽃밭에 누워 로우 앵글을 잡다가 화가 난 꿀벌에게 정통으로 쏘인 영광의 상처에 바른 약입니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('봄바람의 파동', '머릿결이 자연스럽게 흩날리는 ''여신 샷''을 만들어주기도 하지만, 삼각대를 엎어버리는 돌풍이 되기도 합니다.', 'item', 'common', '3d3b35f4-f380-22f6-568b-514444111042', 1.0),
  ('바스라진 단풍잎', '책갈피에 감성 있게 꽂으려 주머니에 넣었으나, 하드코어 라이딩 후 가루가 되어버린 붉은 잔해입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('고프로 마운트 나사', '헬멧에 카메라를 달고 울퉁불퉁한 임도를 달리다 덜덜 풀려 날아가버린, 가장 작고 가장 치명적인 부품입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('메모리카드 케이스', '가을 산의 절경을 4K로 담다 용량이 꽉 차 급하게 갈아 끼우다 흘려버린 텅 빈 투명 플라스틱 케이스입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('액션캠 배터리', '쌀쌀한 가을 날씨에 광탈해버려, 하이라이트 다운힐 구간에서 전원이 꺼지는 비극을 선사한 배신자입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('자전거 벨 부품', '자전거를 세워두고 사진을 찍으려다 나무에 부딪혀 튕겨 나간 경쾌한 ''따릉'' 소리의 파편입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('도토리 껍질', '단풍 샷에 가을 느낌을 더하기 위해 다람쥐의 식량을 잠시 빌려 소품으로 쓴 뒤 버려진 껍데기입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('가을 햇살 조각', '나무 사이로 비스듬히 떨어지는, 카메라 렌즈를 플레어(Flare) 현상으로 가득 채우는 따스하고 나른한 빛의 조각입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('프레임 보호 필름', '낙엽 속에 숨겨진 돌멩이를 밟고 넘어지며 소중한 자전거 프레임을 긁히는 것을 막아준 영웅적인 비닐 조각입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('가을비 젖은 낙엽', '비 내린 다음 날, 타이어에 찰싹 달라붙어 미끄러짐을 유발하는 아찔하고도 아름다운 천연 트랩입니다.', 'item', 'common', '918d9a0a-ce3d-0044-8f55-c6dff8d627ac', 1.0),
  ('얼어붙은 뷰파인더 고무', '영하 15도의 날씨에 카메라를 눈에 대자마자 눈썹과 함께 얼어붙어 떨어져 나간 고무 패킹입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('방한 장갑 한 짝', '셔터를 누르기 위해 두꺼운 장갑을 벗었다가 눈보라에 휩쓸려 날아가 버린, 나머지 한 손의 뼈저린 상실감입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('눈사람의 나뭇가지 팔', '아무도 밟지 않은 설원 인증샷을 위해 정성껏 눈사람을 만들다 똑 부러진 앙상한 나뭇가지입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('핫팩 내용물 가루', '카메라 배터리가 어는 것을 막으려 기기에 칭칭 감아두었다가 터져서 새어 나온 검은 쇳가루 참사입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('성에 낀 필터', '호흡 한 번 잘못 내뱉었다가 렌즈 앞에 거대한 빙벽이 형성되어 모든 피사체를 흐릿하게 만들어버린 안타까운 렌즈입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('스키장갑 클립', '두꺼운 장갑을 손목에 대롱대롱 매달아 주던 플라스틱 고리. 이것이 부러지는 순간 동상과의 전쟁이 시작됩니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('고드름 조각', '모자의 챙 끝에 맺혀 있다가 고개를 숙여 뷰파인더를 보는 순간 카메라 위로 떨어져 박살 난 날카로운 얼음입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('차디찬 눈송이', '플래시를 터트리면 밤하늘의 쏟아지는 별빛처럼 찍히는 완벽한 조연이지만, 옷 속으로 들어가면 끔찍합니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('설원의 고요함', '발이 푹푹 빠지는 소리 외에는 아무것도 들리지 않는, 오직 셔터 소리만이 공간을 가르는 차갑고 무거운 정적입니다.', 'item', 'common', 'b81489b0-383c-0956-ec43-921031148e04', 1.0),
  ('다 쓴 코닥 필름통', '36번의 찰칵거림이 끝난 후, 노란색과 붉은색이 섞인 빈티지 감성을 품고 버려진 아날로그의 껍데기입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('황동 셔터 버튼', '오래된 카메라에 달아둔 부드러운 버튼. 수천 번 눌리며 반들반들하게 길들여진 금속의 촉감이 남아있습니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('낡은 필름 카메라 스트랩', '목에 걸고 동네를 누비며 땀과 세월에 절어 가죽이 갈라지고 끊어져 버린 끈 조각입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('필름 와인더 부품', '사진을 찍고 나서 ''드르륵'' 필름을 감는 찰진 손맛을 책임지던 톱니바퀴. 무리하게 감다 그만 부러졌습니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('현상소 영수증', '일주일을 기다려야 결과물을 볼 수 있다는 설렘과, 현상비가 통장을 비웠다는 슬픔이 동시에 적힌 종이입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('오래된 동네 간판 조각', 'xx이발소''라는 칠이 벗겨진 간판을 필름 감성으로 찍다 툭 떨어져 나온, 재개발 지역의 쓸쓸한 파편입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('길고양이 간식 통', '골목길 스냅의 단골 모델인 길냥이들을 유인하기 위해 흔들어대던, 달그락거리는 소리가 나는 플라스틱 통입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('빛바랜 벽지 조각', '허물어져 가는 빈집의 창틀 너머로 보이던, 70년대 꽃무늬 패턴이 인쇄된 먼지 낀 종이 조각입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('아날로그 감성 한 줌', '초점이 살짝 나가고 빛이 새어 들어왔음에도 불구하고 ''이게 필름의 맛이지''라며 정신 승리하게 만드는 묘한 분위기입니다.', 'item', 'common', '31a58a77-acff-58c9-93b5-0d3ac046aaa6', 1.0),
  ('보랏빛 구름 조각', '해 질 녘, 태양과 어둠이 교차하는 마법의 15분 동안 하늘에 흩뿌려진 환상적인 파스텔 톤의 연기입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('깨진 프리즘', '렌즈 앞에 대고 무지개빛을 연출하려다 바닥에 떨어져 오히려 더 기하학적인 빛의 산란을 만들어내는 유리입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('영원히 남은 필름', '현상액에 담그는 순간 실패한 줄 알았으나, 우연한 빛샘 현상으로 기적 같은 걸작이 되어버린 필름 조각입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('시간이 멈춘 셔터', '빛이 너무 완벽해서 카메라 셔터가 열린 채 그대로 닫히기를 거부해버린, 영원을 담아낸 기계 장치입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('무지개 반사광', '렌즈의 코팅을 뚫고 들어와 사진 정중앙에 플레어를 만들어낸, 삭제할지 말지 고민하게 만드는 일곱 빛깔 원형입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('매직 아워 입장권', '이 몽환적인 시간에 진입하기 위해 추위, 배고픔, 그리고 모기 떼와의 사투를 견뎌낸 자들에게만 주어지는 가상의 티켓입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('천상의 빛무리', '하루 중 그림자가 가장 부드럽고 길어지는 순간. 모든 피사체를 영화의 한 장면처럼 만들어주는 황금빛 입자입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('다차원 카메라 렌즈', '인간의 눈으로는 볼 수 없는, 차원이 겹쳐지는 순간의 일그러짐을 포착해버린 미스터리한 광학 유리입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('환상의 뷰파인더', '눈을 대는 순간 현실의 풍경은 사라지고, 오직 완벽한 구도와 빛으로 재창조된 세계만을 보여주는 작은 창문입니다.', 'item', 'common', '321e6f64-f01d-d74e-9824-a80843e36d0e', 1.0),
  ('빛나는 육각렌치', '자전거 정비의 알파이자 오메가. 이상하게도 가장 자주 쓰는 4mm 렌치만 매번 블랙홀로 사라집니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('찢어진 카드 영수증', '무게 10g을 줄이기 위해 100만 원을 결제한 후, 현실을 부정하며 갈기갈기 찢어 허공에 흩뿌린 슬픈 종이 조각입니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('초경량 카본 파편', '떨어뜨리면 경쾌한 ''텅'' 소리가 나는, 깃털보다 가볍지만 금보다 비싼 마법의 검은색 섬유 덩어리입니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('카본 그리스 튜브', '비싼 카본 부품이 미끄러지거나 깨지는 것을 막아주는 치약. 알갱이가 섞여 있어 바를 때마다 기분이 묘합니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('카본 물통 케이지 볼트', '물통을 고정하는 단 2개의 나사마저 초경량 카본으로 바꾸겠다는 지독한 집착이 낳은 결과물입니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('경량 바테잎 조각', '핸들바에 감는 쿠션마저 가장 얇고 가벼운 것으로 바꾸다 손바닥에 물집이 잡힌 자의 고통이 서려 있습니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('에어로 헬멧 끈', '턱살이 찝히는 고통을 감수하고서라도 공기 저항을 줄이려 바짝 조여 맨 얇은 나일론 끈 조각입니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('카본 프레임 보호재', '수백만 원짜리 프레임에 돌빵이 튀는 것을 막기 위해 덕지덕지 붙여놓은 투명하고 끈적한 필름입니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('통장 잔고의 눈물', '자전거 무게는 깃털처럼 가벼워졌지만, 그 대가로 0에 수렴해버린 통장에서 흘러나온 투명한 슬픔의 결정체입니다.', 'item', 'common', 'f3e7e637-1f47-569a-014a-4cca4c0fe691', 1.0),
  ('티타늄 볼트 한 알', '일반 스틸 나사와 무게 차이는 고작 2g이지만, 은은한 무지갯빛 영롱함에 홀려 개당 만 원씩 주고 산 사치품입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('구워진 티타늄 배기구 조각', '모터사이클이나 자동차 머플러에서 떼어낸 듯한, 고온에 구워져 푸른빛과 보랏빛 그라데이션이 영롱하게 맺힌 금속입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('경량 티타늄 컵 손잡이', '캠핑장에서도 장비병은 멈추지 않습니다. 입술을 데일지언정 무조건 티타늄 시에라 컵을 고집하는 자의 파편입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('은빛 쇳가루', '비싼 부품을 갈아내고 깎아내며 단 1g이라도 덜어내려던 눈물겨운 경량화 작업의 잔해물입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('티타늄 포크 조각', '식사 도구마저 항공우주 소재로 만들어야 직성이 풀리는 극강의 경량 캠퍼가 밥을 먹다 부러뜨린 잔해입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('고강도 합금 파편', '절대 부러지지 않는다는 마케팅 문구를 믿고 극한의 토크로 조이다 퍽 하고 깨져버린 배신감 가득한 조각입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('토크렌치 비트', '비싼 부품을 보호하기 위해 적정 힘으로만 나사를 조이게 해주는 도구. 하지만 마음이 급해 힘으로 돌리다 박살이 났습니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('장비병 초기 진단서', '이 부품만 바꾸면 평속이 2km/h는 오르겠지''라는 치명적인 망상에 빠지기 시작했음을 알리는 가상의 의학 소견서입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('무게 1g의 기쁨', '소고기 한 점보다 비싼 비용을 치르고 얻어낸, 남들은 절대 체감하지 못하는 나만의 미세한 플라시보 효과입니다.', 'item', 'common', '570da6fc-a0b4-4565-011c-5621a9fcb217', 1.0),
  ('해외 배송 송장', '독일, 이탈리아, 영국 등지에서 비행기를 타고 날아온 흔적. 3주간의 애타는 기다림과 조회 앱 새로고침의 증거입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('뾱뾱이(에어캡) 무더기', '영롱한 신상 기어를 안전하게 감싸고 있던 포장재. 언박싱의 흥분이 가라앉은 후 무심하게 터뜨리기 좋습니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('커터칼 칼날', '택배 박스의 봉인 테이프를 가르는 순간, 뇌 속에 엔돌핀을 분비시키는 가장 예리하고 성스러운 도구입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('신상 박스 테이프', '해외 유명 자전거 쇼핑몰 로고가 인쇄된 테이프. 뜯을 때 나는 찌익 소리는 장비병 환자들의 교향곡입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('영문 보증서', '어차피 직구라 AS도 받기 힘들지만, 정품임을 증명하는 은박 로고 때문에 차마 버리지 못하는 종이 쪼가리입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('박스 냄새', '새 제품 특유의 공장 냄새와 수입국의 공기가 섞인 냄새. 숨을 깊게 들이마시는 순간 장비병이 일시적으로 치유됩니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('언박싱 유튜브 대본', '나도 장비 리뷰 유튜버가 되겠다며 야심 차게 카메라를 켰으나, 결국 혼자 흥분해서 소리 지르다 끝난 영상의 흔적입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('관부가세 납부 영수증', '예상치 못한 관세 폭탄을 맞고 손을 떨며 은행 앱으로 송금한 흔적. 직구의 달콤함 뒤에 숨은 쓴맛입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('새 제품의 영롱함', '아직 단 한 번도 아스팔트의 흙먼지를 묻히지 않은, 눈이 부실 정도로 완벽한 무결점의 상태 그 자체입니다.', 'item', 'common', '9232c1ce-cbc6-d314-4739-08b4ceae84c5', 1.0),
  ('중고거래 앱 알림음', '당근~'' 하는 소리와 함께 심박수를 150으로 끌어올리는 알림. 원하던 꿀매물이 떴을 때 발생하는 파블로프의 종소리입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('구겨진 오만 원권', '계좌이체 대신 ''현장 네고''를 시도하기 위해 주머니에서 조심스럽게 꺼내든 꼬깃꼬깃한 현찰입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('직거래 장소 핀', 'XX역 3번 출구 앞''이라는 차가운 텍스트가, 쿨거래를 위해 떨리는 마음으로 서성이는 만남의 광장으로 변하는 위치입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('네고(할인)의 정석 메모', '학생인데 깎아주시면 안 될까요?''부터 ''기름값 빼주세요''까지, 판매자의 마음을 흔들기 위해 정리한 치밀한 대본입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('구매자의 변심', '약속 장소에 다 와서 갑자기 ''아내가 화내서 못 사게 되었습니다''라는 슬픈 문자와 함께 남겨진 허탈함의 조각입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('판매자의 미소', '쿨거래 후 돌아가는 길, 안 쓰는 장비를 팔아 새 장비를 살 자금을 마련했다는 사실에 입꼬리가 씰룩거리는 환영입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('더치페이 영수증', '멀리서 직거래를 하러 온 상대방과 어색하게 국밥 한 그릇을 먹고 각자 계산을 하며 남긴 훈훈한 쪼가리입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('중고 박스 조각', '이전 주인이, 그리고 그 이전 주인이 테이프를 덧붙여 걸레짝이 되었지만 ''풀박스''라는 프리미엄을 지켜주는 상자입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('끌어올리기 버튼', '팔리지 않는 악성 재고를 하루에 한 번씩 위로 끌어올리며 눈물의 가격 인하를 단행한 판매자의 절박함입니다.', 'item', 'common', '31b5587e-d58e-3630-06d9-8a7665ba2ad0', 1.0),
  ('체인 오일 한 방울', '구동계의 부드러움을 위해 도포하다 바닥에 떨어져 지워지지 않는 얼룩을 남기고 아내의 분노를 유발한 검은 액체입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('자전거 그리스', '각종 베어링과 나사산에 처발라 소음을 잡고 윤활을 돕는 구덕구덕한 초록색 혹은 붉은색 연고입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('디그리서 빈 통', '체인에 낀 시커먼 기름때를 녹여버리기 위해 미친 듯이 뿌려대다 코를 찌르는 화학 냄새와 함께 바닥난 스프레이입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('체인 체커기', '체인이 얼마나 늘어났는지 측정하는 금속 도구. 이 도구가 쏙 들어가는 순간, 교체 비용 생각에 한숨이 나옵니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('육각렌치 세트 케이스', '정리 정돈을 사랑하는 미캐닉들이 사이즈별로 예쁘게 렌치를 꽂아두었으나, 항상 자주 쓰는 번호만 비어있는 껍데기입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('펑크 패치 본드', '타이어 튜브를 때우기 위해 바르는 순간, 알싸한 냄새와 함께 손가락을 끈적하게 만들어버리는 접착제 조각입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('더러운 헝겊 조각', '원래는 입지 않는 흰색 면티였으나, 이제는 기어의 찌든 때를 닦아내어 본래 색을 알 수 없는 시커먼 걸레가 되었습니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('바텀브라켓 베어링', '자전거 하단에서 ''딱딱'' 거리는 소음의 원인을 찾기 위해 전체를 분해했다가 결국 다시 조립하지 못하고 남은 구슬들입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('정비 장갑의 기름때', '손을 보호하려 꼈으나, 결국 기름이 다 배어들어 장갑을 벗어도 손톱 밑이 새까맣게 변해버린 영광의 훈장입니다.', 'item', 'common', 'eff21028-8cbc-cce2-4c88-55fdd156d94b', 1.0),
  ('에어로 헬멧 쉴드', '바람을 가르기 위해 헬멧 앞에 장착한 바이저. 마치 다스베이더나 사이보그처럼 보이게 만들어 시선을 강탈합니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('공기저항 측정 데이터', '자전거 무게보다 라이더의 뱃살이 공기 저항에 더 큰 영향을 미친다는 슬픈 진실을 애써 외면한 풍동 실험 결과지입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('꽉 끼는 빕숏의 재봉선', '옷 펄럭임을 없애기 위해 피부에 피가 안 통할 정도로 사이즈를 줄여 입었다가 살에 선명하게 새겨진 고통의 흔적입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('다리털 제모기', '단 0.5초의 공기 저항 단축을 위해, 매끈하고 반짝이는 다리를 만들겠다는 광기로 화장실에서 남몰래 희생시킨 면도기입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('에어로 양말', '발목 위로 올라오는 긴 길이와 세로줄 무늬로 공기를 가르겠다는 의지. 하지만 종아리가 두꺼우면 그냥 답답한 양말입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('에어로 프레임 데칼', '공기 저항을 최소화하기 위해 넙적하게 만들어진 카본 프레임에서 떨어져 나온, 스피드의 상징을 담은 스티커 조각입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('풍동 실험실 먼지', '어마어마한 인공 바람을 만들어내는 실험실에서 떨어져 나온 먼지. 공기를 가르는 최적의 궤적을 기억하고 있습니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('바람을 가르는 소리', '시속 40km가 넘는 속도로 달릴 때 에어로 휠에서 나는 ''우웅- 우웅-'' 하는, 하트비트를 요동치게 만드는 웅장한 공명음입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('숨 막히는 에어로 자세', '최대한 몸을 낮추고 웅크리느라 호흡은 곤란하고 허리는 끊어질 것 같지만, 거울에 비친 멋진 폼 하나로 버티는 순간입니다.', 'item', 'common', 'a61b6b2f-f0ae-b5e8-30ba-7b1827b17cb2', 1.0),
  ('방전된 구동계 배터리', '스마트폰 충전도 모자라 자전거 기어마저 충전해야 하는 시대. 깜빡하고 충전 안 했다가 업힐에서 기어가 고정된 참사의 원흉입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('끊어진 기어 케이블', '과거 아날로그 시대, 찰진 변속감을 주었으나 강한 힘으로 페달을 밟는 순간 ''팅'' 하고 끊어져버린 옛 시대의 유물입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('스프라켓 톱니 조각', '비싼 돈을 주고 바꾼 12단 기어. 너무 강한 파워로 짓밟다 톱니 하나가 똑 부러져 날아간 슬픈 금속 쪼가리입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('전자 변속기 버튼', '딸칵, 마우스 버튼 누르듯 가볍게 누르면 모터가 ''징-'' 소리를 내며 체인을 옮겨주는 신세계의 인터페이스 파편입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('변속 충전 케이블', '라이딩 전날 밤, 잊지 않고 자전거 옆에 쪼그려 앉아 콘센트를 꽂게 만드는 현대 자덕들의 생명줄입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('기름 묻은 풀리', '체인의 방향을 부드럽게 이끌어주는 작은 톱니바퀴. 세라믹 베어링으로 바꿨다며 자가 최면을 걸지만 기름때에 묻히면 다 똑같습니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('체인 핀', '체인의 링크를 연결하는 핵심 부품. 조립하다가 툭 튕겨 날아가 거실 바닥 어딘가로 영원히 사라져버린 블랙홀의 제물입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('부드러운 변속 소리', '지잉- 찰칵''. 전자식 구동계가 한 치의 오차도 없이 다음 기어로 넘어갈 때 내는, 귀르가즘을 유발하는 첨단 기계음입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('업그레이드 핑계거리', '기어가 튀어서 못 타겠어'', ''무릎이 아파서 구동계를 바꿔야 해'' 등 아내의 결재를 받아내기 위한 논리정연한 변명 문서입니다.', 'item', 'common', '5ad4b074-f41c-8d6f-271c-38bff6551fe8', 1.0),
  ('폼건 거품 조각', '자전거를 욕조에 넣고 새하얀 눈송이 같은 거품을 뿌릴 때 느끼는 카타르시스. 묵은 때가 녹아내리는 시각적 희열입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('자전거 전용 세정제', '다이소 퐁퐁을 써도 되지만, 무조건 ''바이크 전용''이라고 적힌 비싼 핑크색 용액을 고집하는 자들의 사치품입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('극세사 수건', '프레임에 기스가 날까 봐 자동차 세차장에서도 가장 부드러운 타월을 골라 아기 다루듯 살살 닦아낸 젖은 수건 조각입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('체인 청소 칫솔', '체인 사이사이를 쑤셔 닦기 위해 희생된 화장실 칫솔. 원래 주인이 누구였는지는 알 수 없을 정도로 시커멓게 변했습니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('광택제 냄새', '세차의 화룡점정. 카본 프레임에 뿌려주면 새 자전거처럼 반짝이게 만드는, 묘하게 중독성 있는 달콤한 왁스 향기입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('프레임 흠집의 슬픔', '깨끗이 씻어내고 나서야 비로소 발견하게 된, 언제 생겼는지 모를 도장면의 스크래치를 보며 쏟아내는 피눈물입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('디스크 로터 클리너', '브레이크에서 삑삑 소리가 나는 것을 막기 위해 미친 듯이 뿌려댄, 금방 증발해버리는 서늘한 알코올 용액의 잔해입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('반짝이는 허브', '면봉까지 동원해 구석구석 닦아내어 거울처럼 얼굴이 비칠 정도로 광을 낸 휠셋 중심축의 빛나는 쇳덩어리입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('세차의 희열', '2시간 동안 땀 뻘뻘 흘리며 자전거를 닦았으나, 내일 아침 라이딩 한 번이면 다시 더러워질 것을 알면서도 짓는 허탈한 미소입니다.', 'item', 'common', 'cd526b91-4088-303d-f157-2db59e663f4d', 1.0),
  ('지름신의 부적', '고민은 배송만 늦출 뿐''이라는 명언이 부적으로 형상화된 아이템. 이 부적을 지닌 자는 결제 버튼을 누를 수밖에 없습니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('할부 결제 동의서', '12개월 무이자면 한 달에 치킨 한 번 안 먹으면 되지''라는 기적의 수학 공식이 적힌 마법의 계약서 쪼가리입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('한도 초과 알림', '최상급 휠셋을 긁으려다 스마트폰 화면에 뜬 붉은색 경고창. 장비병 환자를 현실로 끌어내리는 가장 무서운 메시지입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('아내/남편 몰래 숨긴 영수증', '이거 당근에서 10만 원 주고 산 거야''라는 새빨간 거짓말을 지키기 위해 책갈피 깊숙이 숨겨둔 150만 원짜리 영수증입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('비상금 봉투', '업그레이드를 위해 1년 전부터 책상 서랍 밑에, 겨울 패딩 주머니에 꼬깃꼬깃 모아둔 눈물겨운 비자금 봉투입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('박스 숨길 장소 지도', '거대한 자전거 부품 박스를 가족들 눈에 띄지 않게 베란다 구석, 혹은 회사 창고로 빼돌리기 위해 그린 작전 지도입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('결제 완료 문자의 진동', '드디어 질렀다는 해방감과 다음 달 카드값에 대한 공포가 섞인, 스마트폰의 짧고 강렬한 진동 파동입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('후회 없는 미소', '텅 빈 통장을 바라보며 쓰린 가슴을 부여잡지만, 영롱한 새 장비를 보는 순간 모든 근심이 사라지는 자본주의의 미소입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('통장의 비명', '월급이 스쳐 지나가는 것을 넘어 잔고가 마이너스를 돌파할 때 통장이 내지르는 소리 없는 아우성입니다.', 'item', 'common', '9f370dad-e27a-3a24-2ceb-ffe6e7b464dd', 1.0),
  ('영혼 계약서 조각', '무게를 더 줄일 수만 있다면 악마에게 영혼이라도 팔겠다며 서명한, ''카본 앨리'' 입장 시 요구되는 핏빛 양피지 조각입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('어둠의 카본 마스터 조각', '세상의 모든 부품을 카본으로 구워낸다는 뒷골목 전설의 장인이 버린, 빛을 흡수하는 절대 검정의 찌꺼기입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('무중력의 파편', '카본 앨리 깊숙한 곳에서 거래되는, 손에 쥐어도 무게가 전혀 느껴지지 않아 중력의 법칙을 위배하는 기묘한 물질입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('카본 앨리 입장 토큰', '자전거를 타는 시간보다 쇼핑몰 새로고침 시간이 100배는 많은 자들에게만 은밀하게 발급되는 검은색 동전입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('장비병 완치 증명서(가짜)', '이제 더 이상 바꿀 부품이 없다며 선언할 때 쓰는 증명서지만, 잉크가 마르기도 전에 새로운 신상을 결제하는 위조문서입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('가장 가벼운 깃털', '단 1g의 무게도 허용하지 않는 광신도들이 부적처럼 달고 다니는, 공기보다 가벼운 환상의 깃털입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('티타늄 해골 볼트', '카본 앨리의 지배자가 만든, 티타늄을 깎아 해골 모양으로 세공한 광기와 사치의 끝판왕 나사못입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('환상의 휠셋 스포크', '바람을 베는 것을 넘어 시공간을 베어버릴 듯 얇고 단단한, 달릴 때마다 비명 소리를 내는 전설의 휠 부품입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('지름신의 본체', '모든 장비병 환자들의 머릿속에 기생하며 끊임없이 ''결제해''라고 속삭이는, 황금빛 신용카드를 들고 있는 작은 요정의 형상입니다.', 'item', 'common', '82537749-38f9-ca1e-40f2-df95bc6ea05b', 1.0),
  ('한쪽만 남은 무선 이어폰', '하수구 구멍이나 횡단보도 틈새로 나머지 한쪽이 다이빙해 버린, 상실감과 분노가 서린 반쪽짜리 음향 기기입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('엉켜버린 유선 이어폰', '주머니 속에서 고대 매듭의 저주라도 받은 듯, 풀다 보면 런닝할 시간이 다 지나가 버린다는 악마의 밧줄입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('비 내리는 재즈 카세트테이프', '축축하게 젖은 아스팔트 위를 달릴 때 들으면 자신이 마치 누아르 영화 주인공이 된 듯한 착각에 빠지게 만드는 낡은 테이프입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('메트로놈 부품', '발소리와 심박수를 정확히 일치시키기 위해 째깍거리던 도구. 기계적인 완벽함에 집착하다 박살 난 흔적입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('180 BPM 플레이리스트', '재생하는 순간 다리가 제멋대로 미친 듯이 구르기 시작해 멈출 수 없게 만드는, 도핑 테스트에 걸려야 마땅한 마약 같은 음원 목록입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('스마트폰 암밴드 조각', '팔뚝에 꽉 조여 피를 안 통하게 만들면서도, 오직 음악을 듣겠다는 일념 하나로 땀에 푹 절여진 나일론 천입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('볼륨 조절 버튼', '숨이 차오를수록 음악 소리를 더 키우기 위해 미친 듯이 꾹꾹 누르다 결국 함몰되어 버린 슬픈 버튼입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('땀에 젖은 이어팁', '귀에서 자꾸 미끄러져 빠지는 것을 막기 위해 수십 번 다시 쑤셔 넣다 짭짤한 결정체가 맺혀버린 실리콘 쪼가리입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('심장 박동의 파동', '드럼 비트와 완전히 동기화되어, 가슴 밖으로 터져 나올 것 같이 ''쿵쿵'' 울리는 생명의 강렬한 진동입니다.', 'item', 'common', 'e5036bea-62f5-2124-3ce3-00b9a4a56970', 1.0),
  ('노이즈 캔슬링 마이크 부품', '세상의 모든 잡음을 지워버리기 위해 역위상 파동을 쏘아대다 과부하로 타버린 최첨단 기술의 잔해입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('차단된 자동차 경적 소리', '등 뒤에서 울린 위협적인 경적 소리지만, 노이즈 캔슬링의 완벽한 방어막에 막혀 의미 없는 공기 진동으로 산화한 흔적입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('무음의 공간', '이어폰을 켜는 순간 세상이 수조 속으로 빨려 들어간 듯 먹먹해지는, 외부와 철저히 단절된 진공의 상태입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('이어폰 충전 케이스', '유닛은 귀에 꽂혀 있지만 정작 이 껍데기를 어디에 뒀는지 기억나지 않아 집 안을 발칵 뒤집게 만든 주범입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('블루투스 페어링 신호', '페어링이 완료되었습니다''라는 기계음과 함께 비로소 달릴 준비가 끝났음을 알리는 뇌 속의 경쾌한 스위치입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('바람 소리 필터', '강풍이 불 때마다 이어폰 마이크를 강타하는 ''파스스스'' 소리를 걸러주지 못해 결국 유저의 고막을 테러한 솜뭉치입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('완벽한 고요함', '발이 땅에 닿는 진동마저 음악에 묻혀, 자신이 우주 공간을 유영하고 있다고 착각하게 만드는 абсолютный 0의 상태입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('음소거 버튼', '누군가 길을 물어볼 때 다급하게 누르려 했으나, 땀 묻은 손가락이 미끄러져 대답을 무시한 무례한 러너가 되게 한 버튼입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('놓쳐버린 타인의 인사', '건너편에서 반갑게 손을 흔들며 외친 지인의 인사가 노이즈 캔슬링에 먹혀버려, 다음날 해명 문자를 보내게 만든 민망한 조각입니다.', 'item', 'common', '0b57f851-6ed6-9ab4-5ad6-17a5732dd802', 1.0),
  ('Lo-Fi 테이프 늘어난 줄', '따뜻하고 먹먹한 질감을 내기 위해 의도된 건지, 아니면 진짜로 테이프가 늘어난 건지 알 수 없는 힙한 소음의 근원입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('새벽 감성 필터', '새벽 5시 물안개 낀 강변을 달리며, 내 안의 모든 감수성을 끌어올려 마치 뮤직비디오를 찍는 듯한 필터를 씌워주는 조각입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('턴테이블 바늘 조각', '아스팔트 위를 달릴 뿐인데 묘하게 ''지지직''거리는 LP판의 백그라운드 노이즈를 뇌내 재생시켜 주는 빈티지 부품입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('빗소리 ASMR 조각', '실제 비는 오지 않지만 마음의 평화를 얻기 위해 인공적으로 깔아둔 화이트 노이즈. 자칫하면 졸음 러닝을 유발합니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('레코드판의 먼지', '깨끗한 디지털 음원을 거부하고 굳이 거칠고 탁한 소리를 찾기 위해 바늘과 함께 긁혀 나간 아날로그의 잔해입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('낡은 MP3 플레이어', '스마트폰 스트리밍 대신 15년 전 감성을 느끼겠다며 서랍장 구석에서 발굴해 낸, 재생 버튼이 뻑뻑한 벽돌 기기입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('따뜻한 베이스 드럼 소리', '심박수를 무리하게 올리지 않고, 안개 낀 아침 산책의 속도에 완벽하게 맞춰주는 부드럽고 묵직한 템포의 파편입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('흐릿한 가로등 불빛', '아직 해가 뜨지 않은 어스름한 골목길, 로파이 비트와 완벽한 조화를 이루며 나를 비춰주던 노란 불빛의 조각입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('차분한 발소리', '달리기의 경박함을 버리고, 비트에 맞춰 바닥을 스치듯 가볍게 밀어내는 명상적인 스텝의 리듬입니다.', 'item', 'common', '2ca773eb-0497-42d9-55ba-38ef994a86b1', 1.0),
  ('일렉기타 피크', '고경사 업힐에서 폭발하는 하드락 기타 리프를 치며 올라가다 피가 끓어올라 허공에 던져버린 날카로운 플라스틱 조각입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('찢어진 락 밴드 티셔츠', '땀 배출 기능 따윈 전혀 없지만, 오직 록스피릿을 위해 입었다가 땀범벅이 되어 장렬히 전사한 검은색 면티입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('헤드뱅잉의 땀방울', '달리면서 메탈 음악에 심취해 고개를 과도하게 흔들다 목에 담이 올 뻔한, 치명적인 열정의 결정체입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('터져버린 앰프 조각', '이어폰 볼륨을 최대로 키우고 고막을 학대하며 극한의 아드레날린을 뽑아내다 유닛의 스피커가 사망한 흔적입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('찢어지는 샤우팅 소리', '다리가 풀려버릴 것 같은 마의 구간에서 고통을 잊기 위해 보컬과 함께 마음속으로 괴성을 지른 흔적입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('드럼 스틱 조각', '허벅지가 터질 것 같은 고통을 더 빠른 더블 베이스 드럼 비트로 짓눌러버리며 부러져나간 상상 속의 나뭇조각입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('징 박힌 가죽 팔찌', '스포츠 용품이 아니라 락 페스티벌용 굿즈지만, 자전거 핸들바를 잡을 때 전사의 기운을 준다며 억지로 찬 장신구입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('피 끓는 아드레날린', '음악의 클라이맥스에 도달하는 순간, 근육의 피로를 강제로 셧다운시키고 평속을 5km/h 올려버리는 호르몬입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('업힐 정복의 함성', '마침내 정상에 올랐을 때, 음악의 엔딩 코드와 함께 자신도 모르게 입 밖으로 튀어나온 짐승 같은 포효입니다.', 'item', 'common', 'af495f17-d454-01d5-7f12-1c437ad945e3', 1.0),
  ('로우 배터리 경고음', '뚜-두-둑''. 한참 페이스가 좋았는데 귀를 때리는 불길한 신호음. 음악이 멈출까 봐 심장이 내려앉습니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('단선된 충전 케이블', '라이딩 전날 밤 분명히 꽂아뒀는데 접촉 불량으로 1%도 충전되지 않는 대참사를 유발한 배신자입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('초조한 손톱 자국', '배터리 잔량 3%에서 결승점까지 음악이 버텨주길 기도하며 스마트폰 액정을 미친 듯이 두드린 흔적입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('방전된 보조배터리', '이어폰을 살리려 가져왔으나 이 녀석마저 텅 비어있어 완벽한 절망을 선사한 무거운 쇳덩어리입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('멈춰버린 음악', '결국 전원이 꺼지며 세상이 일순간 정지한 듯한 침묵. 발걸음이 갯벌에 빠진 것처럼 무거워집니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('침묵의 공포', '음악의 마취 효과가 사라지자 그동안 무시했던 거친 숨소리와 무릎의 통증이 현실로 밀려오는 끔찍한 순간입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('살아난 주변 소음', '바람 소리, 자동차 소리, 사람들의 대화 소리가 갑자기 폭포수처럼 쏟아져 뇌를 어지럽히는 불쾌한 현실 복귀입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('달리기 페이스 붕괴', '비트라는 메트로놈을 잃어버리자마자 1km 페이스가 30초 이상 뚝 떨어져 버리는, 멘탈 붕괴의 명백한 증거입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('보조배터리를 향한 갈망', '집에 두고 온 충전 케이스를 떠올리며, 남은 거리를 맨정신으로 어떻게 달려야 할지 막막해하는 영혼의 외침입니다.', 'item', 'common', '76e66f30-a4a1-0f10-0b9d-ba256f4411c5', 1.0),
  ('야광봉 조각', '밤의 한강 공원을 대형 클럽으로 만들어버리는 EDM 드롭 구간에서, 상상 속으로 미친 듯이 흔들어대다 부러진 야광 막대입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('미러볼 파편', '신나는 전자음이 고조될 때 땀구멍마다 빛이 반사되어 마치 온몸이 사이키델릭한 조명을 뿜어내는 듯한 환각의 잔해입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('클럽 스탬프 자국', '어제 이태원 클럽에서 춤추다 찍힌 도장을 안 씻고 그대로 달리기 시작해, 땀에 번져 기괴한 문신이 되어버린 잉크 자국입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('형광 페인트 자국', '야간 러닝 크루들이 단체로 맞춰 입은 네온 컬러 티셔츠에서 떨어진, 어둠 속에서 유일하게 생동하는 빛의 파편입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('베이스 드롭의 순간', '쓰리, 투, 원, 렛츠고!''와 함께 전자음이 터져 나오는 찰나, 몸이 용수철처럼 튕겨 나가는 마법의 버튼입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('레이저 조명 조각', '자전거 전조등 불빛마저 화려한 무대 조명으로 보이게 만드는, 극도의 흥분 상태에서 목격한 빛의 궤적입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('DJ 믹서 노브', '환희를 더 끌어올리기 위해 상상 속에서 볼륨과 베이스를 최대로 꺾어버린 가상의 디제잉 장비 부품입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('환각의 멜로디', '숨이 너무 차올라 산소가 부족해진 뇌가 EDM 비트와 결합하여 들려주는, 세상에서 가장 기분 좋은 사이렌 소리입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('터져 나오는 엔돌핀', '고통의 임계점을 넘은 순간, 음악과 호흡이 하나가 되어 몸 전체에 소름이 돋으며 쏟아지는 천연 마약입니다.', 'item', 'common', '034f75b5-d39d-dfad-d2e9-058295089aa0', 1.0),
  ('소니 워크맨 부품', '스마트폰 스트리밍을 거부하고 허리춤에 묵직한 카세트 플레이어를 차고 달리는 극강의 힙스터가 흘린 플라스틱 조각입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('A면에서 B면으로 넘기는 소리', '테이프가 다 돌아가고 ''철컥'' 하며 뒤집히는 그 3초의 공백. 이 짧은 정적이 아날로그 마니아들에겐 최고의 휴식 시간입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('믹스테이프 라벨지', '나만의 런닝 플레이리스트를 만들기 위해 볼펜으로 꾹꾹 눌러 쓴 글씨가 땀에 번져 알아볼 수 없게 된 종이 스티커입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('AA 건전지 2개', '음악이 느려지기 시작하면 다급하게 근처 슈퍼마켓으로 달려가 샀던, 기계의 생명줄이자 러너의 에너지원입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('테이프 감는 연필', '테이프가 씹혔을 때 육각 연필을 구멍에 꽂고 미친 듯이 빙빙 돌려 심폐 소생술을 시도했던 눈물겨운 도구입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('잡음 섞인 라디오 주파수', '테이프가 지겨워져 켰지만 수신 불량으로 ''지지직'' 소리와 DJ의 목소리가 반반씩 들려오는 추억의 백색소음입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('오래된 팝송 가사지', '7080 디스코 음악에 맞춰 춤추듯 걷기 위해 외우던 가사. 너무 많이 접었다 펴서 너덜너덜해진 종이 쪼가리입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('아날로그의 지지직 소리', '디지털의 쨍한 소리에서는 절대 느낄 수 없는, 따뜻하게 고막을 감싸주는 테이프 특유의 매력적인 노이즈입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('테이프 케이스 힌지', '플라스틱 케이스를 열고 닫다 똑 부러져버려 테이프가 자꾸 굴러떨어지게 만든, 연약하지만 필수적인 연결 부위입니다.', 'item', 'common', '93c93225-cd68-8b93-a56d-f7494955ac01', 1.0),
  ('에어드랍 연결음', '공원에서 우연히 페이스가 맞는 러너를 만나, ''그 노래 뭔가요?''라며 쿨하게 플레이리스트를 공유할 때 울리는 파동입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('음원 스트리밍 캡처 화면', '오늘 나의 완벽했던 달리기 분위기를 자랑하기 위해 인스타그램 스토리에 올릴 음악 재생 화면 스크린샷입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('좋아요'' 하트 조각', '내가 큐레이션한 ''한강 라이딩 필수 플레이리스트''에 누군가 하트를 눌러주었을 때 느끼는 큐레이터의 벅찬 자부심입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('공유된 재생 목록', '숨차서 뒈질 것 같을 때 듣는 노동요''라는 다소 과격한 제목으로 러닝 크루 단톡방에 뿌려진 MP3 리스트의 조각입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('새로운 음악 취향', '평소라면 절대 듣지 않았을 장르지만, 다른 마에스트로에게 영업 당해 달릴 때만큼은 최고로 치게 된 낯선 비트입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('이어폰 한쪽 나눠 끼기', '함께 보폭을 맞추며 달리는 파트너와 이어폰을 한쪽씩 나누어 끼고 유선으로 연결된, 땀내 나지만 낭만적인 순간입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('음악 추천 메모장', '신호대기 중 옆 사람의 음악이 너무 신나 보여 용기 내어 제목을 물어본 뒤 다급하게 적어둔 메모의 파편입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('동기화된 비트', '각자의 이어폰을 끼고 있지만 똑같은 플레이리스트를 재생하여 두 사람의 발소리가 하나의 악기처럼 딱 맞아떨어지는 마법입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('음악 친구의 탄생', '취향이 완벽히 일치하는 플레이리스트를 공유하며, 이름도 모르지만 평생의 러닝 메이트를 얻은 듯한 훈훈한 텔레파시입니다.', 'item', 'common', 'add1460a-b2e0-e3c3-ef88-3faaaf098940', 1.0),
  ('지휘봉 조각', '빗속을 질주하는 자신의 모습이 비운의 마에스트로 같다고 느껴 허공에 지휘하듯 손을 휘젓다 꺾어버린 상상 속의 막대기입니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('젖은 악보 조각', '비 내리는 날 장엄한 베토벤 교향곡을 들으며 달리는 순간, 눈앞의 풍경이 한 편의 거대한 오케스트라 악보로 변하는 환각입니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('첼로 현의 파편', '웅장하고 구슬픈 첼로 선율이 심장을 후벼 팔 때, 빗물인지 땀인지 눈물인지 모를 액체가 얼굴을 타고 흐릅니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('바이올린 송진 가루', '몰아치는 폭우 속에서 날카로운 바이올린의 고음이 터질 때마다 페달을 밟는 발에 폭발적인 힘을 불어넣어 주는 마법의 가루입니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('장엄한 교향곡의 클라이맥스', '비바람과 정면으로 맞서 싸우며 다리를 건너는 순간, 합창단이 쏟아내는 장엄한 음성에 자신이 구국의 영웅이 된 듯한 착각에 빠집니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('우비 위로 떨어지는 빗소리', '클래식 선율 위로 톡톡 떨어지는 자연의 빗소리가 천연 타악기처럼 어우러져 완벽한 협주곡을 완성합니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('오케스트라 석의 먼지', '아무도 걷지 않는 젖은 진흙길을 혼자 오케스트라 특등석인 양 착각하며 걸을 때 묻어난 고귀한 흙먼지입니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('피아노 건반 조각', '물웅덩이를 피하기 위해 이리저리 뛰어오르는 발걸음이 마치 피아노 건반 위를 가볍게 두드리는 손가락 같다는 망상의 파편입니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('우중의 마에스트로', '비가 그치고 클래식이 끝나는 순간, 허공을 향해 양팔을 벌리며 아무도 없는 길 위에서 혼자 인사를 올리는 광기의 흔적입니다.', 'item', 'common', '46557b9f-ebf9-58f6-33a7-47067847ced1', 1.0),
  ('절대 고요의 파편', '음악마저 끄고 궁극의 노이즈 캔슬링 상태로 돌입할 때, 바스락거리는 나뭇잎 소리조차 증발해 버리는 4차원의 조각입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('우주의 배경 복사음', '모든 소음이 사라진 후, 아주 미세하게 귓가를 맴도는 화이트 노이즈. 마치 우주 공간에 홀로 버려진 듯한 착각을 줍니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('심장 박동 악보', '외부 소리가 완벽히 차단되자 내 몸 안에서 나는 혈류의 흐름과 심장 소리만이 유일한 타악기가 되어 연주를 시작합니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('영점 조절기 부품', '속도, 호흡, 정신의 잡음까지 모두 ''0''으로 수렴시켜 무아지경의 상태에 진입하게 해주는 뇌 속의 다이얼입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('완벽한 주파수 파동', '나의 발걸음 진동수와 지구의 자전 주파수가 일치하는 듯한, 엄청난 과대망상이지만 그 순간만큼은 기분 좋은 파동입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('소리 없는 아우성', '극한의 고통 속에서 비명을 지르고 있지만 귀에는 아무것도 들리지 않아, 무성 영화를 찍는 듯한 기괴한 경험의 잔상입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('음표가 된 별빛', '캄캄한 밤하늘을 보며 달릴 때, 시야에 맺힌 별빛들이 고요함 속에서 반짝이는 악보의 음표처럼 보이는 시각적 공감각입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('무지향성 마이크', '주변의 소리를 모두 빨아들여 삼켜버린 뒤 아무것도 뱉어내지 않는, 절대 정적을 만들어내는 보이지 않는 블랙홀 마이크입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('마에스트로의 황금 지휘봉', '소음도, 음악도 모두 지워진 완벽한 공(空)의 상태에서 오직 내 의지 하나만으로 몸의 리듬을 지휘하는 궁극의 경지입니다.', 'item', 'common', '0a4db403-be8c-d32c-e496-af02de24687d', 1.0),
  ('짜먹다 남은 에너지 젤', '마지막 한 방울까지 쥐어짜려다 결국 손과 져지에 다 묻혀버린 끈적하고 씁쓸한 최후의 보루입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('라벨이 벗겨진 부스터 음료', '심박수를 강제로 끌어올리기 위해 마신 정체불명의 음료. 너무 꽉 쥐고 달려 라벨마저 뜯겨 나갔습니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('녹아버린 전해질 캔디', '주머니 속 체온을 견디지 못하고 찐득한 슬라임으로 변해버린 짠맛 포도당 덩어리입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('고카페인 알약 껍데기', '커피 10잔 분량의 각성 효과를 한 알에 응축시킨, 연금술사들의 합법적 도핑 흔적이 남은 빈 캡슐입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('떨리는 손의 파동', '카페인 한계치를 초과한 탓에, 물통을 쥔 손끝에서 멈추지 않고 발생하는 미세한 10Hz의 지진파입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('심장 두근거림의 조각', '운동 때문인지 카페인 때문인지 알 수 없을 정도로 흉곽을 거세게 두드리는 폭주 기관차의 엔진 소리입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('에너지 드링크 캔 뚜껑', '야간 라이딩 전, 탄산과 타우린이 터져 나오는 경쾌한 ''치익'' 소리를 내며 희생된 은빛 뚜껑입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('아메리카노 4샷의 흔적', '피로를 마취시키기 위해 사약처럼 까맣게 타 마신 카페인 폭탄이 남긴 혀끝의 쓴맛 잔상입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('각성 상태의 동공', '카페인 펌핑으로 동공이 확장되어, 어두운 산속에서도 고라니와 눈싸움을 할 수 있을 만큼 또렷해진 시야의 파편입니다.', 'item', 'common', '6c765e6b-90a8-471b-91b2-b9d9f0e4b7c1', 1.0),
  ('전해질 파우더 가루', '물에 타 먹기 귀찮아 그냥 입에 털어 넣었다가 기침과 함께 사방에 흩날려버린 마법의 짠 가루입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('물통에 묻은 소금기', '땀으로 흠뻑 젖은 손으로 물통을 잡았다가 수분이 증발하며 하얗게 결정화된 짭짤한 흔적입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('마그네슘 캡슐', '밤마다 찾아오는 끔찍한 종아리 쥐를 예방하기 위해 잠들기 전 경건한 마음으로 삼키는 수호 알약입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('포도당 캔디 껍질', '봉크(체력 고갈)의 위협이 엄습할 때 다급하게 이빨로 물어뜯어 갈기갈기 찢겨진 비닐 포장지입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('이온음료 페트병', '체액과 가장 가까운 성분이라는 문구를 맹신하며 단숨에 원샷하고 남은, 푸른빛이 도는 찌그러진 플라스틱입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('정밀 저울의 추', '자신만의 완벽한 전해질 배합 비율을 찾겠다며 0.1g 단위까지 집착하는 연금술사의 방구석 실험 도구입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('체액과 동일한 비율의 물방울', '수분, 나트륨, 칼륨의 삼위일체가 완벽하게 맞아떨어져 흡수율 100%를 자랑하는 궁극의 액체 파편입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('칼륨 덩어리', '근육의 수축과 이완을 지휘하는 핵심 미네랄. 바나나 10개를 압축해 놓은 듯한 강력한 에너지를 품고 있습니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('나트륨 결정체', '흘린 땀만큼 무조건 염분을 섭취해야 한다는 강박증이 낳은, 아스팔트 위에서 반짝이는 하얀 소금 결정입니다.', 'item', 'common', '9a534cbe-bbfa-fc2a-c34a-daadc7f7f761', 1.0),
  ('BCAA 가루', '물에 타면 형광펜 색깔로 변하는, 맛은 끔찍하지만 근손실을 막아준다는 믿음 하나로 억지로 삼키는 화학 가루입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('단백질 쉐이커 볼', '뭉친 프로틴을 풀어주기 위해 쉐이커 안에서 쉴 새 없이 벽에 부딪히며 딸그락거리는 철사 공입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('초코맛 프로틴 찌꺼기', '세척을 미루다 쉐이커 바닥에 딱딱하게 굳어버려, 세상에서 가장 끔찍한 악취를 풍기는 암흑 물질입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('근육 이완제 빈 통', '한계를 넘은 대가로 찾아온 근육통을 견디지 못하고 약국의 힘을 빌려 남용해버린 하얀색 약통입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('폼롤러 조각', '뭉친 허벅지를 풀기 위해 눈물을 흘리며 비명을 지르다 너무 강한 압력으로 쥐어뜯긴 스펀지 잔해입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('마사지건 배터리', '허벅지, 종아리, 어깨를 돌아가며 무자비하게 타격하다 과부하가 걸려 장렬히 전사한 배터리 팩입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('회복의 연고', '바르는 순간 코가 뻥 뚫리는 파스 냄새와 함께 피부가 타들어 가는 듯한 착각을 주는 쿨링 젤입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('타트체리 원액 한 방울', '젖산을 분해하고 숙면을 도와준다는 유튜브 광고를 맹신하여 비싼 돈 주고 직구한 시큼한 붉은 묘약입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('근손실의 공포', '오늘 하루 운동을 쉰 대가로 내 근육이 물처럼 녹아내리고 있다는, 연금술사들 특유의 망상이 만들어낸 서늘한 파동입니다.', 'item', 'common', 'e10b45ea-80e8-e382-d2ac-c8e599fe83fe', 1.0),
  ('정체불명의 보라색 액체', 'BCAA, 아르기닌, 크레아틴을 섞어 만들었으나, 색깔만 보면 독극물로 오해받기 딱 좋은 자작 부스터입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('탄산과 젤이 섞인 거품', '에너지 젤을 입에 문 채 콜라를 마셨다가 위장에서 엄청난 팽창을 일으키며 역류할 뻔한 끔찍한 기포입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('경고 문구가 적힌 라벨', '하루 1병 이상 섭취 금지''라고 적혀 있으나, 기록 단축을 위해 가볍게 무시해버린 강력한 보충제의 라벨입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('부글거리는 위장의 소리', '너무 많은 보충제와 젤을 섞어 마신 탓에 배 속에서 화학 반응이 일어나며 울려 퍼지는 불길한 굉음입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('폭발한 쉐이커 뚜껑', '탄산이 섞인 부스터를 넣고 미친 듯이 흔들다 내부 압력을 이기지 못하고 천장으로 치솟아 버린 뚜껑입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('위장약 껍질', '불법(?) 배합의 부작용으로 찾아온 속쓰림을 잠재우기 위해 다급하게 까먹은 하얀 제산제 껍데기입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('화학 실험용 스포이드', '단 한 방울의 배합 오차도 허용하지 않겠다는 연금술사의 집착이 아웃도어 환경에 끌고 나온 이질적인 도구입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('미각 상실의 흔적', '지나치게 시고 쓰고 단 화학 보충제들을 연달아 들이킨 끝에 잠시 혀의 감각이 마비되어 버린 현상입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('초인적인 힘의 3분', '부스터가 혈관을 타고 뇌에 도달한 직후, 페이스가 일시적으로 엄청나게 빨라지는 마법 같은(하지만 곧 꺼질) 시간입니다.', 'item', 'common', '3b22f8f3-4fb6-6719-afb1-4f1c3f74093d', 1.0),
  ('터져버린 파워젤', '뒷주머니에 넣어둔 젤이 엉덩이 체온과 압력을 견디지 못하고 터져 져지 전체를 끈적하게 만든 대참사의 잔해입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('끈적해진 스마트폰 화면', '젤을 짜 먹은 손으로 화면을 만졌다가 터치가 먹통이 되고 영원히 지워지지 않는 지문 자국을 남겼습니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('젤이 묻은 져지 조각', '비싼 의류에 지독하게 달라붙어 세탁기에 3번을 돌려도 특유의 청포도 향이 빠지지 않는 불행한 천 쪼가리입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('개미가 꼬인 자국', '휴식을 위해 벤치에 벗어둔 장갑의 단내를 맡고 달려든 숲속 개미 군단의 치열한 포식 흔적입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('물티슈 껍질', '손의 끈적함을 견디다 못해 편의점으로 달려가 다급하게 뽑아 쓴 뒤 바닥에 버려진 구원의 은박 포장지입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('끈적이는 핸들바 테이프', '젤 묻은 손으로 핸들을 꽉 쥐는 바람에, 탈 때마다 파리끈끈이처럼 손바닥이 달라붙게 된 고통의 그립입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('화가 난 라이더의 입김', '이 끈적한 지옥을 만든 자신을 원망하며 내뱉은 깊은 한숨. 놀랍게도 입김에서도 단내가 납니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('달콤한 냄새의 덫', '지나가는 숲속의 갱단들(너구리, 쥐)마저 홀리게 만드는, 농축된 인공 감미료의 치명적이고 유혹적인 향기입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('젤을 씻어낼 생수', '갈증 해소용이 아니라 오직 손의 끈적함을 씻어내기 위해 아깝게 길바닥에 희생된 귀중한 생수 반 통입니다.', 'item', 'common', 'c23d9c3b-ca2a-bb79-b8ed-76787bddaa47', 1.0),
  ('숙취 해소제 병뚜껑', '어제 마신 폭탄주를 해독하겠다며 라이딩 시작 전 편의점에서 급하게 들이켠 골드 컬러의 뚜껑입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('꿀물 페트병', '알코올로 수분이 말라버린 뇌에 당분을 억지로 쑤셔 넣기 위해 온장고에서 발굴해 낸 따뜻한 생명수입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('헛개수 티백', '땀을 흘려 술을 빼겠다는 위험한 발상으로 물통 가득 진하게 우려낸 구수한 간 해독의 결정체입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('갈증의 사막 조각', '아무리 물을 마셔도 해소되지 않는, 알코올이 체내 수분을 쥐어짜며 만들어낸 입속의 끔찍한 모래사장입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('두통약 알약', '심장 박동이 빨라질 때마다 뇌를 망치로 때리는 듯한 숙취의 고통을 잠재우려 물 없이 삼킨 하얀 구원자입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('흔들리는 초점', '어제의 숙취가 완전히 깨지 않아, 앞사람의 뒷바퀴가 두 개로 겹쳐 보이는 아찔하고도 몽환적인 시각적 오류입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('어제의 후회', '다시는 운동 전날 술을 마시지 않겠다''는 100번째 거짓 맹세가 담긴, 땀과 알코올이 섞인 끈적한 파동입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('해장국집 간판 불빛', '고통스러운 해장 러닝의 끝에 신기루처럼 나타난, 뜨끈한 국물로 모든 죄악을 씻어줄 구원의 붉은 네온사인입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('간 기능 회복의 기도', '페달을 한 번 밟을 때마다 알코올이 1ml씩 배출되기를 간절히 바라는, 연금술사의 처절한 종교적 의식입니다.', 'item', 'common', '5891a1e4-cdf5-ab89-ec23-eb03433a9fb1', 1.0),
  ('바싹 마른 혀의 환각', '보급을 놓쳐 입안에 침이 한 방울도 남지 않았을 때, 혀가 사포로 변해버린 것 같은 끔찍한 환촉입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('텅 빈 물통 캡', '남은 물이 한 방울이라도 떨어질까 봐 거꾸로 들고 미친 듯이 털어대다 깨물어 박살 낸 플라스틱 뚜껑입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('신기루 파편', '땡볕 아스팔트 위에서 저 멀리 편의점 간판이 보인다고 착각하게 만든, 뇌가 열에 익어버린 순간의 환영입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('편의점 에어컨 바람', '극한의 탈수상태에서 자동문이 열릴 때 뿜어져 나오는, 천국의 문이 열리는 듯한 차갑고 성스러운 냉기입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('생수 첫 모금의 짜릿함', '메마른 식도를 타고 차가운 물이 폭포수처럼 흘러내릴 때 전신에 돋는 소름과 엄청난 카타르시스입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('얼음컵 찢는 소리', '편의점 냉동고에서 꺼낸 얼음컵의 비닐 뚜껑을 이빨로 거칠게 뜯어낼 때 나는, 세상에서 가장 경쾌한 파열음입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('사막의 모래알', '물이 없어 침마저 끈적해진 입안에서, 치아끼리 부딪힐 때마다 서걱거리는 불쾌한 건조함의 조각입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('생명수의 물방울', '차가운 포카리스웨트를 마시다 턱을 타고 목덜미로 흘러내린, 아까워서 핥아먹고 싶은 단 한 방울의 이온 음료입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('탈수 증세의 흔적', '다리에 쥐가 오르고 눈앞이 노래지며, 세상의 모든 물웅덩이가 오아시스로 보이는 위험한 생리적 경고음입니다.', 'item', 'common', '9fa66456-8cf3-a2df-39e0-5b86c0917449', 1.0),
  ('노란색 비타민C 알약', '면역력이 떨어지면 다음 날 운동을 못한다는 공포심에 매일 3천 밀리그램씩 털어 넣는 시큼한 결정체입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('오메가3 캡슐 냄새', '관절의 염증을 잡아준다고 굳게 믿고 삼켰으나, 트림을 할 때마다 역하게 올라오는 미세한 생선 비린내입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('멀티비타민 통', 'A부터 Z까지 모든 영양소가 다 들어있어 이거 하나면 천하무적이라고 자위하게 만드는 묵직한 플라스틱 통입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('루테인 껍질', '야간 라이딩 시 시야가 침침해지는 것을 노화가 아닌 영양 부족 탓으로 돌리며 다급하게 까먹은 까만 알약 흔적입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('건강기능식품 영수증', '운동 장비를 사는 것만큼이나 보충제 직구에 많은 돈을 지불하고 있음을 증명하는 긴 종이 쪼가리입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('약통 케이스 부품', '요일별로 정성껏 영양제를 소분해 두었다가, 뚜껑이 열려 배낭 안에 알약 파티를 일으킨 원흉입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('소변이 노랗게 변하는 마법', '몸이 흡수하지 못하고 배출해 버린 과도한 비타민들이 만들어낸, 내가 약을 먹었다는 가장 확실한 시각적 증거입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('과잉 영양의 흔적', '건강해지려다 오히려 너무 많은 영양제를 섞어 먹어 간 수치가 올라가버린 연금술사들의 모순적인 잔상입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('플라시보 효과의 믿음', '약의 실제 효과와 상관없이, ''이걸 먹었으니 오늘 내 체력은 최고일 것이다''라고 뇌를 속이는 강력한 최면술입니다.', 'item', 'common', 'b2eb6a30-d721-42a5-7c87-c499e3fe6392', 1.0),
  ('아껴둔 프리미엄 젤 껍질', '1개에 만 원이 넘는 초고가 젤. 정말 죽을 것 같은 마의 구간을 위해 아끼고 아끼다 뜯어낸 황금빛 포장지입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('눈이 번쩍 뜨이는 효과', '극강의 카페인과 당분이 한꺼번에 흡수되며, 흐릿했던 시야가 4K UHD 화질로 개안하는 마법의 순간입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('마지막 남은 체력 게이지', '0%에 수렴하던 체력 바를 강제로 10% 끌어올려 결승점까지 좀비처럼 걸어가게 만드는 비상 전력입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('아드레날린 앰플', '과학적으로 설명할 수 없지만, 결승선을 눈앞에 두었을 때 뇌가 스스로 합성해 내는 천연 초강력 진통제입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('호흡을 뚫어주는 박하향', '폐에 산소가 부족해 헉헉댈 때, 비강과 기도를 강제로 확장시켜 숨을 쉬게 해주는 독한 민트의 냄새입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('스프린트의 땀방울', '포션의 힘을 빌려 평소라면 절대 내지 못할 속도로 미친 듯이 페달을 밟을 때 허공에 흩날린 땀방울입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('결승선 테이프 조각', '마침내 한계를 극복하고 목표 지점을 통과했을 때, 환희와 함께 끊어낸 가상의 붉은 리본 파편입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('마지막 1방울', '젤 용기 안쪽 깊숙한 곳에 남아있던 단 한 방울의 시럽마저 영혼까지 끌어모아 핥아먹은 처절한 집념의 결과입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('승리의 묘약', '포션과 땀, 그리고 초인적인 의지력이 결합하여 만들어낸, 다시는 재현할 수 없는 그날 그 순간만의 완벽한 도핑 배합입니다.', 'item', 'common', '8134d134-2c0f-74cd-5421-0406a23f30a6', 1.0),
  ('자판기 버튼 조각', '연금술사들의 전설 속 오아시스 자판기에서 가장 낡고 닳은, ''모든 피로 회복''이 적힌 붉은 플라스틱 버튼입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('빛나는 환상의 동전', '이 4차원 자판기에 넣을 수 있는 유일한 화폐. 유저가 극한의 고통을 견뎌냈을 때만 인벤토리에 몰래 드랍됩니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('영생의 물방울', '단 한 모금만으로도 갈증, 근육통, 심박수를 모두 초기화시켜 준다는, 신들이 마셨을 법한 영롱한 액체입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('마법의 엘릭서 빈 병', '내용물은 이미 누군가 마셔버렸지만, 병에 남은 냄새만 맡아도 젖산이 분해되는 기적의 유리구슬 병입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('갈증이 영원히 사라지는 마법', '물을 마시지 않아도 피부로 공기 중의 수분을 흡수할 수 있게 된다는 연금술사들 최고의 과대망상입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('오아시스의 홀로그램', '사막 같은 업힐 끝에 자판기가 보인다고 믿게 만들지만, 손을 뻗으면 스르르 사라져 버리는 잔인한 빛의 장난입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('자판기 동전 반환구 부품', '환상의 동전을 넣었으나 음료 대신 ''아직 한계를 넘지 못했다''는 알림과 함께 동전을 뱉어낸 차가운 쇳조각입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('연금술사의 황금 레시피', '세상 모든 부스터와 이온 음료를 완벽한 비율로 섞어 궁극의 엘릭서를 만들어냈다는 고대 문헌의 찢어진 종이입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('궁극의 에너지 결정체', '더 이상 입으로 먹지 않고 가슴에 품기만 해도 무한한 체력을 공급해 준다는, 포션 연금술의 최종 도달점입니다.', 'item', 'common', 'bf20a6e1-d3e3-989c-b2db-795287c711d6', 1.0),
  ('녹슨 열쇠 꾸러미', '어느 문을 여는지 아무도 모르지만, 달릴 때마다 찰창거리는 소리가 기분 좋은 백색소음을 만들어내는 쇳덩어리입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('태엽이 멈춘 초시계', '스마트워치의 심박수 알림 대신, 딸깍거리는 아날로그 소리로 심장을 뛰게 하던 낡은 은빛 크로노그래프입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('색 바랜 마라톤 배번표', '10년 전 춘천 마라톤에서 달고 뛰었던, 땀에 전 자국과 핀 구멍 4개가 선명하게 남아있는 영광의 종이입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('톱니바퀴 조각', '기계식 시계가 박살 나며 길바닥에 떨어진 정교한 톱니. 시간을 물리적으로 쪼개던 완벽한 기술의 잔해입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('멈춰버린 초침', '디지털의 차가운 숫자를 거부하고, 시간의 흐름을 시각적으로 보여주던 얇고 예리한 금속 바늘입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('가죽 시계줄 파편', '땀에 절어 쿰쿰한 냄새가 나지만, 세월이 지날수록 사용자의 손목에 완벽하게 길들여진 부드러운 가죽 조각입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('태엽 감는 소리', '''찌르륵, 찌르륵''. 러닝 출발 전 초시계 태엽을 감을 때 나는, 아날로그 수집가들만의 성스러운 의식의 소리입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('과거로 돌아가는 시간', 'GPS 기록에 얽매이지 않고 오직 내 숨소리에만 집중할 때, 시공간이 70년대로 워프하는 듯한 환상적인 감각입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('낡은 나침반', '스마트폰 지도가 꺼졌을 때 떨리는 손으로 꺼내 든, 북쪽을 가리키는 바늘이 영 불안하게 흔들리는 황동 기기입니다.', 'item', 'common', '5fe3f8eb-970b-9847-dbfa-9773337c27d5', 1.0),
  ('빛나는 놋쇠 단추', '아스팔트 틈새에 박혀 반짝이던 것을 까마귀처럼 주워 온, 누군가의 낡은 코트에서 떨어져 나온 부적입니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('부러진 은색 옷핀', '배번표를 고정하려다 꺾여버린 핀. 지갑이나 가방 구석에 찔러두면 언젠가 쓸 데가 있다는 맹신의 결과물입니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('깨진 유리구슬', '햇빛을 받으면 영롱한 무지갯빛을 산란시켜, 걷던 발걸음을 멈추고 한참을 바라보게 만든 투명한 파편입니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('모양이 특이한 돌멩이', '아무 쓸모도 없지만 묘하게 사람 얼굴을 닮아 차마 버리지 못하고 주머니에 넣어둔 묵직한 수석입니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('구형 버스 토큰', '지금은 쓸 수 없는 구멍 뚫린 동전. 이걸 주운 날에는 평소보다 페이스가 10초 빨라진다는 미신이 있습니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('누군가의 이니셜이 새겨진 라이터', '''J.H''라는 글자가 각인된 은빛 지포 라이터. 기름은 다 말랐지만 딸깍거리는 뚜껑 소리만큼은 명쾌합니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('동물 모양 지우개', '놀이터 흙바닥에 반쯤 파묻혀 있던 귀여운 토끼 지우개. 목이 잘려 나간 모습이 묘하게 서글픕니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('행운의 2달러 지폐', '길바닥에 버려진 누군가의 낡은 지갑에서 발굴해 낸, 꼬깃꼬깃하게 접힌 초록색 행운의 상징입니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('녹슨 병뚜껑', '모양과 색이 너무 완벽한 빈티지 코카콜라 뚜껑. 가방에 달아두면 완벽한 레트로 룩이 완성됩니다.', 'item', 'common', 'af74bb10-30c7-603d-c6f9-cf7f95533f58', 1.0),
  ('접힌 자국이 낡은 종이 지도', '수백 번을 접었다 펴서 접지선이 다 찢어져 버린, 스마트폰 대신 들고 다니는 지도 마니아들의 바이블입니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('빨간 펜으로 그은 경로', '미리 계획한 루트를 따라 정성껏 그어둔 붉은 궤적. 가끔 길을 잃었을 때 이 선을 보면 화가 치밀어 오릅니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('나침반 바늘', '자기장을 잃어버리고 제멋대로 팽이처럼 빙빙 도는 고장 난 바늘. 이제는 그저 예쁜 쓰레기일 뿐입니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('비에 젖어 번진 잉크', '갑작스러운 소나기에 지도의 등고선과 지명이 수채화처럼 기괴하게 번져버려 강제 미아 모드를 유발한 자국입니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('등고선이 그려진 조각', '지도에서 가장 험난한 고도 차이를 보여주는 부분이 찢겨 나간 파편. 보기만 해도 종아리에 알이 배깁니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('지도 투명 케이스', '비를 막아주겠다며 지도를 감싸둔 비닐 팩이지만, 땀이 차서 안쪽에 습기가 맺혀 글씨를 더 못 보게 만듭니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('물어물어 길을 찾은 기억', 'GPS 음성 안내 대신 동네 어르신께 길을 묻다 엉뚱한 길로 들어서며 완성한, 피곤하지만 사람 냄새 나는 추억입니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('나침반의 오차', '분명 북쪽으로 직진했는데 어째서인지 자꾸 같은 자리를 맴돌게 만드는 기묘한 자기장 왜곡의 산물입니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('오래된 등산로 안내문', '1990년대 폰트로 인쇄되어 지금은 존재하지 않는 샛길을 안내하는, 사람을 혹하게 만드는 위험한 팸플릿입니다.', 'item', 'common', '1b20a1db-9bbb-f790-572b-a4da8622eb92', 1.0),
  ('빛바랜 폴라로이드 사진', '완벽한 런닝 메이트와 함께 찍었으나 화학 약품이 증발해 이제는 흐릿한 유령처럼 보이는 즉석사진입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('일회용 카메라 플래시 부품', '''지잉-'' 하는 충전 소리와 함께 터지며 찰나의 순간을 강렬하게 얼려버렸던 플라스틱 조명 장치의 잔해입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('인화지 냄새', '현상소 봉투를 여는 순간 코끝을 찌르는 특유의 시큼한 화학약품 냄새. 묘하게 중독성 있는 아날로그의 향수입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('사진 속 모르는 사람', '풍경을 찍었는데 구석에 우연히 찍힌 낯선 러너의 모습. 언젠가 다시 마주칠 것만 같은 기묘한 인연의 증거입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('초점이 나간 필름', '숨을 헐떡이며 셔터를 눌러 피사체가 형태를 알아볼 수 없게 흔들렸지만, ''감성''이라 우기기 딱 좋은 컷입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('다이어리에 붙어있던 사진', '종이 테이프로 예쁘게 붙여두었으나 땀방울이 스며들어 너덜너덜해진 채 바닥에 떨어진 일기장 파편입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('오래된 앨범 모서리', '수십 년 전 마라톤 완주 사진들을 모아둔 무거운 가죽 앨범에서 떨어져 나온 금장 보호 장식입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('뷰파인더의 먼지', '렌즈를 닦아도 닦아도 뷰파인더 안쪽에 콕 박혀 시야를 거슬리게 하는 지독한 먼지 한 톨입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('사진 뒷면의 짧은 메모', '''1998년 첫 하프 마라톤''. 빛바랜 모나미 볼펜으로 꾹꾹 눌러쓴 누군가의 벅찬 성취감이 묻어나는 뒷면입니다.', 'item', 'common', 'c79fc13c-4edc-a47e-75b6-5aa613958116', 1.0),
  ('오래된 나무 지팡이 조각', '할아버지가 등산하실 때마다 짚으셔서 손잡이가 닳고 반질반질해진, 세월의 무게가 담긴 목재 파편입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('할아버지의 낡은 모자', '땀띠와 흙먼지가 배어 세탁으로도 지워지지 않지만, 엄청난 산의 기운을 불어넣어 주는 등산 고수의 유품입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('가죽이 해진 자전거 안장 조각', '수십 년간 엉덩이에 완벽하게 맞춰져 어떤 최신형 카본 안장보다 편안하다는 전설의 가죽 덩어리입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('오래된 펌프 부품', '타이어 바람을 넣을 때마다 끼익끼익 비명을 지르지만 묵직한 쇳덩이의 신뢰감을 주는 빈티지 펌프 잔해입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('흑백 사진 속의 미소', '클래식 자전거를 타고 환하게 웃고 계신 할아버지의 사진. 볼 때마다 페달을 밟을 힘을 주는 부적입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('세월의 손때 묻은 손잡이', '오랜 마찰로 원래 색이 무엇인지 알 수 없게 변색된, 타인의 세월을 쥐고 달리는 듯한 기분을 주는 그립입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('녹슨 자전거 종', '따르릉 소리 대신 ''틱, 틱''거리는 둔탁한 소리만 나지만 차마 떼어내지 못한 클래식 자전거의 상징입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('가문의 문장이 찍힌 금속재', '오래된 유럽 브랜드 자전거의 헤드튜브에 붙어있던 영롱하고 고풍스러운 황동 재질의 엠블럼 파편입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('과거로부터 온 편지', '낡은 가방 구석에서 발견된, 할아버지가 젊은 시절 산행 일지를 적어둔 찢어진 수첩 페이지입니다.', 'item', 'common', 'a92d8af5-78cc-9d19-738f-9b6897f0f6d7', 1.0),
  ('비에 젖은 편지 봉투', '누구에게 보내려다 우체통 앞에서 떨어뜨렸는지 모를, 발신인도 수신인도 비에 씻겨 사라진 푸른 봉투입니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('구겨진 우표', '편지 모서리에서 뜯겨 나간 10년 전 발행된 기념우표. 길거리를 굴러다니다 수집가의 주머니에 안착했습니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('사랑 고백이 적힌 종이 조각', '''내일 정류장에서 기다릴게''라고 적힌, 전달되지 못한 누군가의 풋풋한 짝사랑이 비에 젖어 찢긴 조각입니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('누군가의 찢어진 일기장', '''오늘 10km를 처음 쉬지 않고 뛰었다''는 자랑스러운 기록이 담긴 노트 한 장이 바람에 날아왔습니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('펜촉 조각', '만년필로 정성껏 꾹꾹 눌러 쓰다 끝이 휘어져 버려진, 아날로그 필기의 거친 마찰감이 서린 금속 파편입니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('우체국 소인 자국', '빨간색 스탬프가 찍혀 날짜와 장소를 증명하는 종이 쪼가리. 이것만 있으면 시간 여행을 하는 기분이 듭니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('읽지 않은 마음', '단단히 밀봉되어 차마 열어볼 수 없는 누군가의 진심이 담긴 편지. 함부로 뜯을 수 없어 가방 깊숙이 봉인했습니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('보내지 못한 엽서', '해외의 아름다운 산 풍경이 인쇄되어 있으나 뒷면은 텅 비어있는, 길 잃은 여행자의 엽서 한 장입니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('잉크 냄새', '비에 젖은 종이를 말렸을 때 은은하게 올라오는 만년필 잉크 특유의 화학적이고도 로맨틱한 향기입니다.', 'item', 'common', '79ab7cbd-a18e-d9d3-d340-940bece93f32', 1.0),
  ('바퀴 빠진 미니카', '동네 꼬마가 놀이터 벤치에 두고 간 녹슨 미니카. 한때는 누구보다 빨리 트랙을 달렸을 퇴역 레이서입니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('팔이 부러진 인형', '흙투성이가 된 채 화단에 누워있던 작은 플라스틱 인형. 달릴 때마다 주머니 안에서 서글프게 달그락거립니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('태엽 감는 장난감 쥐', '등에 달린 태엽을 감으면 뽈뽈거리며 바닥을 기어 다니던 양철 장난감. 이제는 녹이 슬어 움직이지 않습니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('색이 벗겨진 팽이', '수많은 전투의 흔적으로 나무 칠이 다 벗겨진 구형 팽이. 모서리가 뭉툭해져 더 이상 회전하지 못합니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('어린 시절의 향수', '망가진 장난감을 주웠을 때, 퇴근길의 퍽퍽함을 잠시 잊고 코흘리개 시절 놀이터로 돌아간 듯한 아련한 파동입니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('장난감 병정의 총', '주인공을 지키기 위해 싸우다 총구만 똑 부러져 바닥에 나뒹구는 초록색 플라스틱 조각입니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('모래놀이 플라스틱 삽', '주말 공원에서 아이들이 성을 쌓고 놀다 버려둔 노란색 삽. 이제는 수집가의 무쓸모 컬렉션이 되었습니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('녹슨 스프링', '어디서 떨어져 나왔는지 모를 작은 용수철. 꾹 누르면 여전히 탱- 하고 튕겨 나갈 것 같은 탄성을 지녔습니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('잃어버린 동심의 조각', '스마트폰에 밀려 길거리에 방치된 아날로그 장난감들이 뿜어내는, 어른들만 느낄 수 있는 서글픈 감촉입니다.', 'item', 'common', 'b2d04ee7-5749-f60d-a7c6-dfc6ffdb391d', 1.0),
  ('''철거'' 글씨가 적힌 붉은 락카 조각', '재개발로 무너져가는 텅 빈 골목길 담벼락에서 떨어져 나온, 한 동네의 사형 선고가 적힌 시멘트 파편입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('오래된 이발소 회전간판 파편', '빙글빙글 돌며 동네의 랜드마크 역할을 하던 삼색 원통에서 깨져 나온 색 바랜 아크릴 조각입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('문패 조각', '누구누구의 집이라고 자랑스럽게 걸려있었으나 포크레인에 의해 박살 나버린 청동 재질의 이름표 파편입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('담벼락의 시멘트 덩어리', '런닝 코스로 애용하던 조용한 골목길이 영원히 사라지는 것을 기리기 위해 몰래 챙겨온 차가운 돌덩어리입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('버려진 슬레이트 지붕 조각', '비가 오면 타닥타닥 정겨운 빗소리를 내던 파란색 지붕재. 이제는 흉물스러운 공사장 쓰레기가 되었습니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('재개발 안내문', '골목 입구 전봇대에 붙어있던, 동네 주민들의 삶을 숫자와 보상금으로 치환해버린 차가운 종이 쪼가리입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('빈집의 자물쇠', '주인이 떠난 텅 빈 집의 대문을 굳게 잠그고 있던, 이제는 아무것도 지키지 못하는 무거운 쇳덩어리입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('사라져가는 동네의 사진', '포크레인이 들어오기 전날, 아날로그 카메라로 황급히 담아낸 익숙하고도 낯선 우리 동네의 마지막 영정 사진입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('먼지 쌓인 골목길의 바람', '건물이 무너지며 일어난 흙먼지 속에서, 수십 년간 그곳에 머물던 사람들의 체취가 흩어지는 쓸쓸한 바람결입니다.', 'item', 'common', 'd564cbd5-c667-7c03-e55c-90c83d228add', 1.0),
  ('오래된 책 냄새', '헌책방 골목을 달릴 때 콧속으로 훅 밀려 들어오는, 종이가 산화하며 뿜어내는 바닐라와 먼지가 섞인 포근한 향입니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('누렇게 변색된 종이', '버려진 책 더미에서 찢겨 날아온 페이지. 바스락거리는 촉감이 마치 낙엽을 만지는 듯 건조하고 따뜻합니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('밑줄 그어진 문장', '''포기하고 싶을 때 한 걸음 더 내디뎌라''. 책의 이전 주인이 붉은색 색연필로 삐뚤게 그어둔 강렬한 동기부여의 흔적입니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('책갈피로 쓰인 말린 나뭇잎', '소설책 사이에 수십 년간 갇혀 있다가 완벽하게 납작해진, 바스라지기 직전의 아름다운 가을의 박제입니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('헌책방 영수증', '20년 전에 타자기로 찍혀 인쇄된 듯한 영수증. 지금은 500원짜리 책이 당시에는 얼마였는지 보여주는 타임캡슐입니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('낡은 가죽 양장본 조각', '비싼 책의 표지에서 떨어져 나온 고급스러운 가죽 쪼가리. 주머니에 넣어두면 은은한 가죽 냄새가 번집니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('모르는 이의 독서 노트', '책 귀퉁이에 빼곡하게 적어둔 이전 주인의 일기와 상념들. 훔쳐보는 듯한 은밀한 재미를 선사합니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('인쇄 잉크의 흔적', '활판 인쇄 시절 종이에 깊게 파인 글자 자국들. 디지털 화면에서는 절대 느낄 수 없는 입체적인 텍스트의 촉감입니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('사연이 담긴 책 표지', '누군가에게 선물하며 앞장에 적어둔 애틋한 헌사가 남아있는, 버리기엔 너무 무거운 감정이 담긴 책등 조각입니다.', 'item', 'common', 'e6399dcb-6a46-48e5-3251-7a1493d5f55d', 1.0),
  ('기억의 보관함 열쇠', '세상의 모든 잃어버린 물건들이 모인다는 전설의 분실물 센터 999번 방의 문을 열 수 있는 유일한 황금 열쇠입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('999번 방의 문고리 조각', '수많은 사람들의 후회와 그리움이 손때로 묻어 반질반질하게 닳아버린, 이계로 통하는 황동 문고리의 파편입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('영원히 잃어버리지 않는 나침반', '바늘이 북쪽이 아니라 내가 가장 되찾고 싶은 잃어버린 기억의 방향을 가리킨다는 마법의 나침반입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('누군가의 가장 소중했던 기억', '분실물 센터 허공을 떠도는 빛나는 구슬. 살짝 만지면 타인의 가장 행복했던 순간이 머릿속으로 흘러들어옵니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('분실물 센터 접수증', '''당신의 잃어버린 열정을 보관 중입니다''라고 적힌 기묘한 종이. 이것을 찢는 순간 포기했던 취미를 다시 시작하게 됩니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('차원을 넘나드는 먼지', '4차원 분실물 센터의 바닥에 깔린, 햇빛을 받으면 은하수처럼 반짝이며 떠오르는 신비로운 우주 먼지입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('기억을 되찾은 자의 눈물', '분실물 센터에서 자신의 가장 소중한 옛 물건을 되찾은 자가 흘린, 따뜻하고 짠맛이 나는 환상의 액체 결정입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('환상의 아날로그 테이프', '재생하면 한 번도 들어보지 못한 노래가 나오지만 이상하게도 가사를 모두 따라 부르게 되는 최면의 카세트테이프입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('모든 것을 기억하는 시계', '바늘이 거꾸로 돌아가며 잃어버린 물건을 떨어뜨린 정확한 시간과 장소로 유저를 안내해 주는 분실물 센터의 궁극 유물입니다.', 'item', 'common', '8405301c-5dfe-4e35-55f6-1d869d1a1a91', 1.0),
  ('포장도 안 뜯은 요가매트', '두 달 전 당찬 결심과 함께 배송받았으나, 아직 투명 비닐조차 벗기지 않아 새것의 향기를 간직한 원통형 물체입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('한 짝만 남은 수면양말', '이불 밖으로 나가려는 발목을 포근하게 붙잡고 늘어지는, 침대 요정들의 치명적인 마취 도구입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('내일의 다짐 메모', '매일 밤 잠들기 전 ''내일은 무조건 뛴다''고 적어두지만, 아침이 되면 거짓말처럼 기억에서 삭제되는 마법의 포스트잇입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('멈춰버린 알람 시계', '새벽 6시부터 5분 간격으로 울려대다 주인의 무자비한 스매싱을 맞고 영원한 침묵에 빠진 불쌍한 시계입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('따뜻한 이불솜 조각', '세상에서 가장 무거운 중력을 발생시켜 유저를 결박하는, 폭신하고 따뜻한 악마의 솜뭉치입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('새벽 러닝 취소 문자', '같이 뛰기로 한 러닝 메이트에게 ''배가 아프다''며 황급히 전송한, 비겁하지만 달콤한 변명의 흔적입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('비 온다는 핑계의 일기예보', '강수 확률 10%를 핑계 삼아 합법적으로 운동을 쉴 수 있게 해주는, 기상청이 내린 구원의 캡처본입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('미개봉 런닝화 박스', '박스만 열면 국가대표가 될 것 같지만, 신발끈 묶기가 귀찮아 신발장 구석에 고이 모셔둔 관상용 아이템입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('자기합리화의 조각', '오늘 하루 쉰다고 근손실이 오진 않아''라며 스스로에게 강력한 최면을 거는 심리적 방어막입니다.', 'item', 'common', '9b6ac9a0-f665-923f-e778-3b82f6eb5bbe', 1.0),
  ('옷걸이가 된 런닝머신 부품', '빨래를 널기에 최적화된 각도와 튼튼한 프레임을 자랑하는, 세상에서 가장 비싸고 거대한 건조기 부품입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('먼지 쌓인 덤벨 손잡이', '마지막으로 들어 올린 지 언제인지 기억조차 나지 않아, 손잡이 홈마다 뽀얗게 먼지가 내려앉은 철덩어리입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('홈쇼핑 구매 영수증', '쇼호스트의 화려한 언변에 홀려 ''이것만 있으면 나도 몸짱''이라 착각하며 결제했던 씁쓸한 과거의 증명서입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('스트레칭 밴드의 끊어진 자국', '과도한 열정으로 너무 강하게 당기다 끊어져 버린 고무줄. 그 이후로 모든 스트레칭이 강제 종료되었습니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('거미줄 친 요가볼', '거실 구석에 굴러다니다 방치되어, 이제는 거미들의 아늑한 트램펄린 놀이터가 되어버린 거대한 짐볼입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('사용 설명서 쪼가리', '홈트 기구 조립 직후 박스와 함께 가차 없이 버려진, 사실상 읽어본 적 없는 종이 쓰레기입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('리모컨과 한 몸이 된 손', '소파에 누워 넷플릭스를 고르느라 손에서 리모컨이 떨어지지 않는, 사이보그화가 진행 중인 기괴한 파편입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('TV 앞의 안락함', '바닥에 매트를 깔고 홈트를 시작하려다, 방영 중인 예능 프로그램에 홀려 그대로 주저앉게 만드는 마의 결계입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('홈트레이닝 영상 썸네일', '하루 10분 전신 박살''이라는 유튜브 썸네일만 쳐다봐도 이미 살이 빠진 것 같은 착각을 유발하는 이미지입니다.', 'item', 'common', '8fbd67f1-27d9-39de-4f75-d44628a2d7dc', 1.0),
  ('택도 안 뗀 고어텍스 자켓', '비닐조차 뜯지 않아 빳빳함을 유지하고 있는, 당장 에베레스트를 등반해도 될 법한 70만 원짜리 바람막이입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('신발장에 방치된 클릿슈즈', '한 번 넘어지고 클릿 공포증에 걸려 다시는 페달에 발을 올리지 못한 비운의 플라스틱 신발 밑창입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('결제 취소 기한 지난 영수증', '환불을 미루고 미루다 결국 기간이 지나버려, 울며 겨자 먹기로 소장하게 된 강제 구매 확정서입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('언박싱 안 된 택배 박스', '안에 든 것이 운동 기구라는 것을 알기에, 뜯는 순간 운동을 시작해야 한다는 부담감에 외면당한 상자입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('화려한 디자인의 스포츠 타올', '땀을 닦은 적은 단 한 번도 없고 오직 거울 셀카를 찍을 때 어깨에 걸치기 위해 구매한 패션 소품입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('장비 자랑용 인스타 캡처', '산에는 안 갔지만 장비 세팅만큼은 엄홍길 대장님 부럽지 않은, #등산스타그램 태그가 달린 허세 가득한 사진입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('운동복 핏 확인용 거울 파편', '운동보다 예쁜 레깅스 핏이 더 중요한 유저가 매일 전신을 비춰보다 지문이 잔뜩 묻어버린 거울 조각입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('할부금의 압박', '장비는 이미 창고에 처박혔으나 12개월 무이자 할부는 여전히 현재 진행형인, 매달 찾아오는 통장의 고통입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('장비만은 국가대표급 부심', '실력은 동네 뒷산 수준이지만 장비의 스펙만큼은 K2 정상 정복을 노리는 자들의 뻔뻔하고도 눈부신 자부심입니다.', 'item', 'common', 'c0f08c17-27fd-d830-bc7c-ad928a7387f9', 1.0),
  ('기름 튄 회식 영수증', '법카로 먹는 소고기''라는 유혹에 넘어가 헬스장을 가볍게 포기하게 만든 치명적인 종이 쪼가리입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('취소된 헬스장 예약증', '오늘 야근이 생겨서요''라는 핑계로 PT 선생님에게 다급하게 전송한 취소 메시지의 잔해입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('삼겹살 냄새가 밴 넥타이', '운동복 대신 정장을 입고 불판 앞에서 삼겹살을 뒤집다 고기 냄새가 섬유 속 깊숙이 스며든 직장인의 애환입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('소주병 뚜껑', '프로틴 쉐이크 대신 오늘 하루의 스트레스를 날려줄 차가운 알코올의 봉인을 해제한 은빛 금속 파편입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('건배사의 파동', '우리의 건강을 위하여!''라며 술잔을 부딪치는, 헬스장과는 거리가 먼 모순적이고도 유쾌한 외침입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('상사의 칭찬(가짜)', '김 대리 오늘 수고했어, 한잔해''라는 한마디에 운동의 의지가 모래성처럼 무너져 내린 허탈한 순간입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('내일은 꼭 가겠다는 다짐', '소주 3병을 마신 뒤 불타는 얼굴로 ''내일은 아침에 헬스장 간다''고 외치는, 아무도 믿지 않는 취중 진담입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('대리운전 명함', '식당 입구에서 주머니에 쑤셔 넣은 작은 종이. 이것을 쥐는 순간 오늘 밤의 운동은 영원히 물 건너갔음을 의미합니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('회식 핑계의 안도감', '운동을 안 가도 되는 정당하고 완벽한 핑계가 생겼을 때, 마음속 깊은 곳에서 피어오르는 짜릿한 해방감입니다.', 'item', 'common', 'c038d31d-68de-b808-7a0f-7251d3373f53', 1.0),
  ('미세먼지 경고 앱 화면', '미세먼지 농도 ''보통''임에도 불구하고 ''나쁨''이 될 것 같다며 선제적으로 운동을 포기하게 만든 빨간색 아이콘입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('태풍 핑계용 꺾인 우산', '실제로는 이슬비만 내리지만, 마음속에는 거대한 태풍이 몰아치고 있다며 러닝을 취소하게 한 부서진 우산입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('폭염 주의보 문자 캡처', '에어컨 아래에서 ''오늘은 너무 더워서 쓰러질지도 몰라''라며 안전을 핑계로 이불과 물아일체된 증거물입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('조금 내린 빗방울', '아스팔트를 1mm도 채 적시지 못한 가랑비지만, ''비 맞으면 감기 걸려''라는 거대한 핑계거리로 둔갑한 물방울입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('추위를 핑계 삼은 핫초코 빈 잔', '영하 1도밖에 안 되지만 얼어 죽을 것 같다며, 따뜻한 전기장판 위에서 핫초코를 타 먹은 끈적한 흔적입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('황사 마스크 끈', '호흡기가 약하다는 이유로 한강 라이딩을 포기하고 서랍 속에 처박아둔 KF94 마스크의 늘어난 고무줄입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('날씨 탓 백과사전 페이지', '더우면 더워서, 추우면 추워서, 흐리면 흐려서 안 나가는 날씨 핑계계의 권위자가 쓴 찢어진 사전 조각입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('실내 환기 금지 표지판', '바깥공기가 안 좋다며 문을 꼭꼭 닫아걸고 방구석에서 뒹굴거리는 것을 정당화해 주는 방어벽입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('창밖을 보는 아련한 눈빛', '운동화까지 다 신었으나 창밖의 흐린 하늘을 보며 ''역시 오늘은 아니야''라고 중얼거리는 쓸쓸한 시선입니다.', 'item', 'common', '2435fd53-affe-5cc7-f8e9-0d7d54ff94c0', 1.0),
  ('새해 첫날의 다짐 적힌 다이어리', '1월 1일, 호기롭게 ''바디프로필 도전''이라고 적었으나 1월 3일 이후로 백지가 되어버린 비운의 노트입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('먼지 쌓인 헬스장 회원 카드', '지갑 가장 안쪽에 방치되어 바코드 색이 다 바래버린, 출입을 허락받았으나 사용되지 못한 플라스틱 카드입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('사물함 자물쇠 열쇠', '헬스장에 고이 모셔둔 샤워바구니와 운동화를 6개월째 봉인하고 있는, 녹이 슬어버린 황동색 열쇠입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('기부 천사 감사장(환상)', '헬스장 관장님이 매달 자동 결제되는 당신의 회비로 새 머신을 샀다며 마음속으로 보내는 가상의 상장입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('환불 불가 규정서', '가족의 사망이나 이민 외에는 환불 불가''라는 무시무시한 조항 때문에 울며 겨자 먹기로 회원을 유지하게 만드는 종이입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('PT 강사의 안부 문자', '회원님, 요즘 왜 안 오시나요? ㅠㅠ''라며 죄책감을 유발하는, 스팸 문자보다 무서운 카카오톡 메시지입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('오랜만에 간 헬스장의 낯설음', '반년 만에 헬스장 문을 열었을 때, 바뀐 기구 배치와 몸짱들 사이에서 느끼는 지독한 이방인의 감각입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('근육통의 공포', '첫날 하체 운동 후 화장실 변기에 앉을 때마다 비명을 질렀던 끔찍한 기억이 만들어낸 강력한 심리적 트라우마입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('샤워실 샴푸 냄새', '운동은 안 하고 샤워만 하고 가려고 헬스장에 들렀을 때 몸에 밴, 헬스장 공용 비누의 익숙한 향기입니다.', 'item', 'common', 'ffe967a2-e423-1a20-7016-25c300a540c2', 1.0),
  ('유튜브 쇼츠 재생 버튼 조각', '운동화 끈을 묶다 무심코 누른 1분짜리 영상이 2시간의 타임워프를 일으키게 만든 악마의 빨간색 버튼입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('뜨거워진 스마트폰 배터리', '침대에 누워 알고리즘의 바다를 헤매느라 발열이 시작된, 주인의 게으름을 온몸으로 견디고 있는 기기입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('소파의 푹신한 쿠션 솜', '한 번 엉덩이를 대면 블랙홀처럼 몸을 빨아들여 절대 일어날 수 없게 만드는 치명적인 마약 쿠션의 파편입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('배달 앱 VIP 쿠폰', '러닝 앱 대신 배달의 민족을 켜고 야식을 고르다 획득한, 운동의 의지를 완벽하게 꺾어버리는 할인권입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('시간 순삭의 블랙홀', '분명 8시였는데 눈 깜짝할 사이에 11시가 되어버린, 스마트폰이 만들어낸 무시무시한 시공간의 왜곡 현상입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('알고리즘의 늪 조각', '내가 좋아할 만한 먹방 영상만 기가 막히게 추천해 주어 다이어트 의지를 박살 내는 AI의 은밀한 덫입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('눈의 피로감', '달려서 난 땀 대신, 어두운 방 안에서 스마트폰 블루라이트를 정통으로 맞아 뻑뻑해진 안구의 건조함입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('풀려버린 운동화 끈', '나가려고 단단히 묶었으나 스마트폰을 보며 소파에 기대앉다 스르륵 풀려버린, 의지 박약의 시각적 증거입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('자괴감의 한숨', '자정이 되어서야 오늘 하루도 폰만 보며 날렸다는 사실을 깨닫고 내뱉는, 아주 깊고 짙은 헛바람입니다.', 'item', 'common', '989fc342-1d1d-4b82-657d-81a7190df782', 1.0),
  ('3일째 달력의 ''X'' 표시', '작심삼일의 고비를 넘기지 못하고 붉은색 펜으로 쫙 그어버린, 실패의 역사가 기록된 달력 쪼가리입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('근육통 파스 껍질', '이틀 동안 무리하게 운동한 대가로 찾아온 근육의 비명을 잠재우려 다급하게 뜯어낸 서늘한 파스 잔해입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('바닥난 의지력의 부스러기', '활활 타오르던 첫날의 열정이 단 72시간 만에 하얗게 재가 되어 바스라진, 쓸쓸한 정신력의 가루입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('달콤한 침대의 유혹', '온몸이 쑤시는 3일 차 아침, 이불이 평소보다 10배는 푹신하게 느껴지며 몸을 감싸 안는 마법의 포옹입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('스스로에게 한 거짓말', '근육도 쉬어줘야 성장한다''며 아무런 과학적 근거 없이 자체 휴식일을 선포하게 만든 자기기만의 조각입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('작심 4일의 실패', '마의 4일 차를 넘지 못하고 원래의 나태한 자아로 완벽하게 회귀해 버린, 인간 본성의 씁쓸한 승리표입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('피자 배달 영수증', '스트레스 받은 나에게 상을 주겠다며 다이어트 3일 차 밤에 치즈 크러스트 피자를 시켜 먹은 타락의 영수증입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('다이어트 포기 선언문', '먹고 죽은 귀신이 때깔도 좋다''며 닭가슴살을 쓰레기통에 처박고 선언한 위대한 항복의 문서입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('소파와 물아일체된 흔적', '운동을 포기한 순간, 몸의 긴장이 풀리며 소파 가죽의 굴곡에 완벽하게 일치해 버린 편안한 신체 탁본입니다.', 'item', 'common', '6cca30db-b0b2-48d3-bcb9-9de34491f063', 1.0),
  ('치킨 뼈 무더기', '분명히 ''오늘까지만 먹고 내일부터 진짜 다이어트''라고 외치며 맹렬하게 발골해 낸 처참한 양념치킨의 잔해입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('치킨 무 국물 자국', '치킨 상자를 뜯다 방바닥에 흘린 새콤달콤한 국물. 다이어터를 유혹하는 치명적인 향기를 품고 있습니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('최후의 만찬 영수증', '매일 밤이 ''다이어트 전 마지막 식사''라며 족발, 보쌈, 엽떡을 번갈아 시켜 먹어 탄생한 기적의 카드 내역서입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('거짓말 탐지기 바늘', '내일부터 진짜 살 뺀다''는 말을 듣자마자 바늘이 미친 듯이 요동치다 기계가 터져버린 진실의 파편입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('다이어트 자극 사진 찢어진 것', '냉장고에 붙여두었던 복근 모델의 사진. 배가 고파 눈이 뒤집힌 유저가 홧김에 북북 찢어버렸습니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('체중계의 오작동 부품', '올라갈 때마다 늘어나는 숫자를 현실로 받아들이지 못하고 ''기계가 고장 났다''며 내동댕이친 체중계의 잔상입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('콜라 빈 페트병', '양심상 제로 콜라를 마셨다며 위안 삼았지만, 이미 치킨 두 마리를 해치운 뒤라 아무 의미 없어진 빈 플라스틱입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('마지막 남은 피자 꼬투리', '남기면 아깝다는 핑계로 배가 부른데도 억지로 밀어 넣다 결국 뱉어낸 딱딱한 밀가루 빵조각입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('내일로 미루는 주문', '다이어트는 원래 내일부터 하는 거야''라는 전 세계 모든 아가리어터들의 공통된 종교적 주문의 파동입니다.', 'item', 'common', '6d5e8172-a74c-8b22-7952-7ff95ea566af', 1.0),
  ('부서진 ''내일''의 결계 조각', '수만 번 ''내일 하자''고 속삭이던 게으름의 유리벽을 깨부수고 밖으로 나섰을 때 튕겨 나간 투명한 파편입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('현관문을 연 엄청난 용기', '안락한 방구석을 버리고 차가운 바깥 공기를 마주하기 위해 문고리를 돌렸던 땀방울 맺힌 기적의 순간입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('땀방울이 맺힌 첫 수건', '침대에 누워있던 자가 무려 30분이나 달리고 돌아와 이마를 닦아낸, 소금기가 서린 위대한 면직물입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('떨리는 다리의 진동', '오랜만의 운동으로 근육이 놀라 후들거리지만, 그 떨림조차 살아있음을 느끼게 해주는 기분 좋은 파동입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('기적의 성취감 조각', '작심삼일 클럽원이 드디어 해냈다는 환희에 차올라 거울을 보며 지은, 세상에서 가장 뿌듯한 미소의 파편입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('섬데이 탈출 티켓', '영원히 반복되던 ''언젠가(Someday)''라는 지옥의 타임루프를 끊어내고 ''오늘''을 쟁취한 자에게 주어지는 황금 티켓입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('승리의 첫 걸음걸이', '운동화 끈을 질끈 묶고 아스팔트 위를 내디딘 첫 발자국. 달 착륙만큼이나 유저 개인에게는 거대한 도약입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('작심 4일차의 기적', '마의 3일을 넘기고 4일째 되는 날에도 어김없이 현관을 나섰을 때 터져 나오는, 스스로에 대한 경이로움입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('게으름을 이긴 마법의 펜', '내일''이라고 적힌 다이어리의 글자를 북북 지워버리고 ''지금 당장''이라고 덮어쓴, 의지력이 응축된 볼펜입니다.', 'item', 'common', '2ca772e9-1ef9-938a-f793-b8e0e75c4914', 1.0),
  ('발광하는 운석 조각', '숨이 턱 끝까지 차오른 순간, 밤하늘에서 떨어져 내 발앞에 꽂힌 은은한 네온그린 빛의 우주 암석입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('설인의 털뭉치', '한여름 도심 한복판 아스팔트 위에서 발견된, 절대 녹지 않는 서늘한 냉기를 뿜어내는 기괴한 흰색 털입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('시간이 멈춘 회중시계', '러너스 하이에 진입한 정확한 순간에 초침이 멎어버려, 영원한 쾌락의 찰나를 봉인해 둔 은빛 시계입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('일그러진 공간의 파편', '분명 직진했는데 제자리로 돌아오게 만든, 보이지 않는 공간의 주름에서 뜯겨 나온 투명하고 날카로운 조각입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('차원을 넘은 먼지', '우리 우주에는 존재하지 않는 원소 기호로 이루어진 먼지. 햇빛을 받으면 기하학적인 패턴으로 춤을 춥니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('중력이 없는 돌멩이', '손바닥 위에 올려두면 슬그머니 허공으로 떠오르려 하는, 뉴턴의 사과를 비웃는 건방진 자갈입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('빛을 빨아들이는 천 조각', '어떤 강한 플래시를 비춰도 칠흑 같은 어둠만 반환하는, 시공간의 찢어진 구멍을 덮고 있던 섬유입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('기하학적인 금속 큐브', '끝없이 회전하며 모양을 바꾸는 정육면체. 바라보고 있으면 묘하게 페이스 조절이 완벽해지는 최면 효과가 있습니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('4차원 나침반의 바늘', '동서남북이 아니라 ''과거''와 ''미래''를 가리키며 미친 듯이 요동치는, 방향 감각을 상실한 기이한 나침반 부품입니다.', 'item', 'common', 'e8af7880-700b-5070-7c59-af45a2b4b7db', 1.0),
  ('정체불명의 세 발가락 발자국', '공원 진흙탕에 선명하게 찍힌 거대한 발자국. 지구상의 어떤 도감에서도 이 생물체의 정체를 찾을 수 없습니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('야광 수액 한 방울', '밤의 산길에서 나무줄기를 타고 흐르던 형광 보랏빛 액체. 만지면 심장 박동이 일시적으로 200까지 치솟습니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('외계의 깃털', '새의 깃털 같지만 금속성 광택이 나고 미세한 전류가 흐르는, 대기권을 뚫고 날아온 미확인 비행 생명체의 파편입니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('알 수 없는 뼈 조각', '분명 어제까지는 없었던 등산로 한가운데에 놓인, 형태를 가늠할 수 없는 미끈하고 서늘한 골격의 일부입니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('전파 방해의 노이즈', '이 파편을 주머니에 넣으면 무선 이어폰에서 음악 대신 정체불명의 외계어 같은 지지직거림이 들려옵니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('보라색 피가 묻은 잎사귀', '야생동물의 것이라고 하기엔 점성이 너무 강하고 색이 기괴한, 숲속 어둠 속에서 벌어진 기묘한 사투의 흔적입니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('미확인 동물의 울음소리 녹음', '녹음기를 켜둔 것도 아닌데 스마트폰 음성 메모에 저절로 저장되어 있는, 고막을 긁는 듯한 기괴한 주파수의 파동입니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('환각의 버섯 포자', '숨을 크게 들이마신 순간 코로 들어와, 눈앞의 아스팔트를 무지개색 우주로 바꿔버린 강력한 외계 포자입니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('투명해지는 비늘', '빛의 굴절을 완벽하게 조작하여 시야에서 사라지는 카멜레온 같은 특성을 지닌 미확인 파충류의 비늘입니다.', 'item', 'common', '2a1f8b3f-366d-63b7-ddc2-72772b8fa42b', 1.0),
  ('공중에 떠오르는 물방울', '물통에서 짜낸 물이 바닥으로 떨어지지 않고 슬로우 모션처럼 위로 솟구쳐 오르는, 중력 역전 현상의 조각입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('위로 떨어지는 사과 조각', '나무에서 떨어진 사과가 땅이 아닌 하늘을 향해 치솟다 나뭇가지에 걸려버린, 아이작 뉴턴이 오열할 만한 파편입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('거꾸로 핀 꽃잎', '뿌리가 하늘을 향하고 꽃잎이 땅을 파고드는 기괴한 형태로 자라난, 중력의 법칙을 완전히 무시한 식물입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('중력계의 부서진 바늘', '이 구역에 들어선 순간 기압과 중력이 엉망이 되어 바늘이 허공을 뚫고 튀어나가 버린 기계 장치의 잔상입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('가벼워진 체중의 환각', '마치 달 표면을 걷는 것처럼 발걸음이 솜털처럼 가벼워져 한 번의 도약으로 5미터를 점프하게 만든 착각의 파동입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('하늘로 솟구친 먼지', '달릴 때마다 일어난 흙먼지가 가라앉지 않고 회오리치며 하늘로 빨려 올라가는 기이한 시각적 오류 현상입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('역방향의 바람소리', '바람이 앞에서 뒤로 부는 것이 아니라, 내 몸속에서 시작되어 바깥으로 뿜어져 나가는 듯한 묘한 청각적 환각입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('나침반의 미친 회전', '북쪽을 잃어버리고 팽이처럼 미친 듯이 빙빙 돌다 결국 자기장 오류로 모터처럼 타버린 자성의 잔해입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('시공간의 왜곡된 파동', '오르막길인데 내리막길처럼 페달이 가벼워지는, 물리 엔진에 심각한 버그가 발생한 듯한 쾌감의 결정체입니다.', 'item', 'common', 'f0991102-e59b-9d99-a61f-6a547814c1bc', 1.0),
  ('푸른 도깨비불의 잔해', '자정의 공동묘지 근처에서 너울거리며 나의 페이스를 끌어올리던 차갑고 푸르스름한 플라즈마 불꽃의 흔적입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('싸늘한 한기의 조각', '한여름 푹푹 찌는 날씨에도 불구하고 목덜미를 스치고 지나가며 온몸에 소름을 돋게 한 영하의 공기 덩어리입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('홀린 듯한 발걸음', '분명 집으로 가려 했는데 정신을 차려보니 한 번도 와본 적 없는 낯선 터널 입구에 서 있게 만든 빙의의 파편입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('등골이 서늘한 땀방울', '운동으로 흘린 뜨거운 땀이 아니라, 누군가 등 뒤에서 나를 지켜보고 있다는 공포에 식은땀으로 변해버린 액체입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('기묘한 웃음소리의 진동', '음악 소리를 뚫고 희미하게 들려온, ''그 속도밖에 안 돼?''라며 비웃는 듯한 정체불명의 기괴한 주파수입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('버려진 서낭당의 부적', '길 잃은 자를 유인한다는 오래된 당산나무 밑에서 굴러다니던, 피처럼 붉은 글씨가 적힌 바스락거리는 종이입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('안개 낀 강가의 냄새', '도심 한가운데를 달리고 있음에도 코끝을 진하게 찌르는, 축축하고 비린 물안개의 기묘한 후각적 환각입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('도깨비 감투의 실오라기', '이것을 쥔 순간 지나가는 사람들과 자전거가 나를 전혀 보지 못하고 투명 인간 취급을 하는 기이한 현상이 일어납니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('환영을 쫓던 자의 나침반', '길이 없는 벽을 향해 계속해서 직진하라고 지시하여 헌터를 이계의 문턱까지 끌고 갔던 위험한 길잡이입니다.', 'item', 'common', 'c9ec86be-da81-d2a0-fda5-6b8e55d4bfd0', 1.0),
  ('평행우주의 나와 마주친 거울 조각', '쇼윈도에 비친 내 모습이 달리고 있는 게 아니라 소파에 누워 치킨을 먹고 있는 평행우주의 참상을 보여주는 거울입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('다른 세계의 신문지 쪼가리', '바람에 날려온 낡은 신문. 날짜는 오늘인데 기사 내용은 ''지구, 3차 세계대전 발발''이라고 적혀있는 소름 돋는 종이입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('데자뷔의 뇌파 조각', '처음 달리는 길인데 10년 전 이 자리에서 똑같이 넘어졌던 기억이 생생하게 뇌리에 박히는 기억 오류의 파편입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('기억 조작의 파편', '분명 5km를 달렸다고 생각했는데 시계는 1분을 가리키고 있는, 인지 시간과 물리 시간이 완벽히 엇갈린 충격입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('알 수 없는 언어의 메모', '주머니 속에 언제 들어왔는지 모를 쪽지. 지구상의 어떤 언어학자도 해독할 수 없는 기하학적 문자로 빼곡합니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('두 개의 그림자', '가로등은 하나인데 바닥에 비친 내 그림자가 두 개로 갈라져 각기 다른 동작을 하고 있는 시각적 공포입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('다른 차원의 배번표', '내 이름이 적혀있지만 내가 한 번도 나간 적 없는 2099년도 화성 마라톤 대회의 구겨진 홀로그램 배번표입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('익숙한 낯선 길의 흙', '매일 뛰던 한강공원인데 갑자기 하늘이 보라색으로 변하고 강물이 거꾸로 흐르던 아주 짧은 1초의 틈새에서 묻은 흙입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('나침반이 가리키는 다른 우주', '북쪽이 아니라 ''선택하지 않았던 과거의 후회'' 방향을 가리키며 유저의 마음을 후벼 파는 기이한 자성 장치입니다.', 'item', 'common', '5122e7e5-3356-f8f5-4891-468556cc1e75', 1.0),
  ('녹아내린 시계 바늘', '초현실적인 스피드로 공간을 돌파할 때 시간의 저항을 이기지 못하고 살바도르 달리의 그림처럼 녹아버린 초침입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('꼬여버린 GPS 트랙 로그', '직진만 했을 뿐인데 지도 앱에는 내가 뫼비우스의 띠 모양으로 영원히 제자리를 돌고 있는 것으로 기록된 버그입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('타임루프의 흔적', '같은 교차로를 세 번이나 지나쳤음에도 주변 풍경과 신호등 색깔마저 똑같이 반복되던 지독한 시간 갇힘의 잔상입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('젊어진 세포의 파편', '빛의 속도에 근접하게 달렸다는 과대망상 덕분에, 상대성이론에 의해 내 세포가 3시간 정도 젊어졌다고 믿는 플라시보 조각입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('과거로 돌아간 영수증', '주머니에서 나온 편의점 영수증. 날짜가 무려 1998년으로 찍혀 있어 내가 방금 웜홀을 통과했음을 증명합니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('미래에서 온 동전', '길거리에서 주운 동전. 연도가 ''2077년''으로 각인되어 있으며 만지면 미세하게 따뜻한 진동이 느껴집니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('시간의 뫼비우스 띠', '아무리 달려도 결승선이 멀어지기만 하는, 시간의 끝과 시작이 연결된 악몽 같은 무한 루프의 파동입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('늙어버린 하루살이', '나의 1분이 이 곤충에게는 100년의 시간으로 왜곡 적용되어, 내 어깨에 앉자마자 백골이 되어 바스라진 흔적입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('시간의 미로 입장권', '물리적 거리가 무의미해지고 오직 의지만으로 시공간을 점프할 수 있게 해주는, 4차원 미로의 홀로그램 티켓입니다.', 'item', 'common', '6ef1c7fd-2973-43d2-912c-d37eed254b60', 1.0),
  ('진공 상태의 유리병', '병뚜껑을 여는 순간 주변 10미터 반경의 모든 소음을 빨아들여 일시적인 абсолютный 고요를 만들어내는 기묘한 아이템입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('메아리가 흡수된 벽돌', '터널에서 소리를 질렀으나 반사되지 않고 벽돌이 소리를 통째로 삼켜버려 으스스함을 자아낸 건축 자재의 파편입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('소리 없는 천둥의 파편', '눈앞에서 번개가 번쩍였으나 고막을 찢는 파열음 대신 완벽한 정적만이 귀를 때린, 청각을 상실한 찰나의 기억입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('말라버린 비명소리', '다리에 쥐가 나 괴성을 질렀지만 입 밖으로 아무 소리도 나오지 않아 무성 영화의 주인공이 된 듯한 기괴한 파동입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('절대 고요의 깃털', '귀에 꽂고 달리면 타이어 마찰음도, 숨소리도 완벽히 소거되어 자신이 우주 공간을 유영한다고 착각하게 만드는 물건입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('입 모양만 남은 메가폰 조각', '군중 속에서 누군가 나를 향해 확성기로 소리치고 있으나 소리는 오지 않고 입술의 움직임만 기괴하게 슬로우 모션으로 보입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('귀를 먹먹하게 하는 기압차', '마치 심해 10,000미터로 가라앉은 듯 갑자기 고막이 먹먹해지며 세상과 단절되는 4차원의 투명한 장벽입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('음소거된 자동차 경적', '대형 트럭이 코앞에서 경적을 울렸으나, 스위치를 끈 것처럼 아무 소리도 나지 않아 심장만 철렁 내려앉게 한 환상입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('침묵을 깨는 단 하나의 심장소리', '온 세상의 소리가 사라진 후, 오직 내 흉곽을 때리는 ''쿵- 쿵-'' 하는 심장 박동만이 유일한 메트로놈이 된 숭고한 순간입니다.', 'item', 'common', '4dbe2c2a-2a77-e70d-4790-0770b60050fb', 1.0),
  ('말하는 돌멩이 조각', '힘들어 주저앉았을 때 ''고작 그거 뛰고 쉬냐?''라며 내 머릿속에 직접 텔레파시를 쏘아댄 건방진 광물입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('걸어 다니는 나무뿌리', '안개 낀 산길, 발밑의 나뭇가지들이 뱀처럼 꿈틀거리며 길을 비켜주거나 발목을 낚아채려 했던 끔찍한 환각의 잔해입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('환각을 일으키는 포자 가루', '새벽 이슬과 섞여 공기 중으로 퍼지며, 가로등을 요정으로 보게 만들고 전봇대와 춤추게 만든 위험한 물질입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('안개꽃의 요정 날개', '산안개 속에서 나를 안내해 주던 빛나는 형체가 남기고 간, 사실은 거미줄에 맺힌 이슬방울의 시각적 착각입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('미쳐버린 나침반', '길을 안내하는 대신 유저의 가장 큰 공포가 서린 곳으로 자침을 돌려버리는, 뇌파와 연결된 악마의 길잡이입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('환영의 성벽 벽돌', '저 멀리 거대한 성이 보여 달려갔으나, 다가갈수록 스르르 연기처럼 흩어져 버린 신기루가 남긴 뼛가루입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('웃고 있는 낙엽', '밟을 때마다 바스락거리는 소리가 마치 나를 비웃는 어린아이의 웃음소리처럼 들려 등골을 서늘하게 한 식물 찌꺼기입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('안개 숲의 기묘한 버섯', '이 버섯을 밟은 순간 시야가 180도 뒤집혀 하늘을 발로 밟고 땅을 올려다보며 달리게 된 강력한 인지 왜곡의 근원입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('이성을 잃은 자의 일기장', '''안개가 나를 부른다''는 문장으로 빽빽하게 채워진, 환각 숲에서 길을 잃은 어느 헌터의 광기 어린 기록물입니다.', 'item', 'common', '4cec3af4-2067-9e4f-1e2a-e0472f381b08', 1.0),
  ('고통이 증발한 눈물', '육체의 한계를 뚫고 나갔을 때 고통이 환희로 바뀌며 뺨을 타고 흘러내린, 짭짤하지 않고 달콤한 맛이 나는 액체입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('영혼이 빠져나간 껍데기 조각', '극한의 질주 도중 자아가 육체와 분리되어, 기계처럼 달리고 있는 내 몸을 하늘에서 내려다본 유체이탈의 파편입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('유체이탈의 끈', '내 영혼이 날아가지 못하게 육체와 간신히 연결해 주던 은빛 실. 이 끈이 끊어지는 순간 영원히 우주 미아가 됩니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('초월자의 황금빛 땀방울', '통각이 마비되고 무아지경에 이르렀을 때 이마에서 뿜어져 나온, 햇빛을 받으면 진짜 황금처럼 찬란하게 반짝이는 땀입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('한계 돌파의 부서진 자물쇠', '''여기까지만 하자''고 외치던 뇌의 방어 기제를 완벽하게 부수고 나아갈 때 뇌내에서 울려 퍼진 파열음의 조각입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('마비된 통각 세포', '근육이 찢어지는 듯한 고통이 일순간 스위치를 끈 것처럼 사라지고, 온몸이 깃털처럼 가벼워진 의학적 미스터리 현상입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('허공을 걷는 발자국', '발바닥이 아스팔트에 닿지 않고 지면 1cm 위를 부양하며 미끄러지듯 나아가는, 무협지의 경공을 실현한 발자취입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('신선이 된 자의 수염', '물아일체의 경지에 도달하여 산의 정기를 마시는 순간, 속세의 욕망이 사라지고 해탈의 경지에 오른 자의 허연 털입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('육체를 굽어보는 시선', '세상의 모든 번뇌를 벗어던지고, 가쁜 숨을 몰아쉬는 미천한 내 육신을 제3자의 입장에서 관조하는 초월적인 시각입니다.', 'item', 'common', '689bb588-c6f6-b417-169a-6648aac77b85', 1.0),
  ('순백의 문고리 조각', '모든 미스터리의 종착지. 육체의 고통을 넘어선 무의식의 4차원, ''화이트 룸''의 문을 열기 위해 잡았던 눈부신 손잡이입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('눈이 멀 것 같은 하얀 빛무리', '화이트 룸에 입장한 순간 시야를 덮친 절대적인 백색광. 모든 기억과 형상을 새하얗게 탈색시켜 버리는 근원의 빛입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('무의식의 차원 지도', '길도 없고 건물도 없는 무한한 백지의 공간에서 나아갈 방향을 알려주는, 오직 마음속으로만 읽을 수 있는 지도입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('아무것도 적히지 않은 백지', '화이트 룸의 책상 위에 놓여있던 종이. 어떤 펜으로 써도 먹혀들지 않으며 오직 진정한 깨달음만으로 글자를 새길 수 있습니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('완벽한 무(無)의 파편', '소리, 냄새, 고통, 쾌락 등 인간의 모든 감각이 ''0''으로 수렴되는 абсолютный 진공의 상태를 고체화한 투명한 결정입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('화이트 룸의 입장 열쇠', '육체의 한계를 3번 연속 돌파하고 자아를 버린 자에게만 뇌내에서 몰래 발급되는 신경 전달 물질의 궁극적 조합입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('존재가 지워진 자의 이름표', '화이트 룸의 평화로움에 취해 현실로 돌아오는 것을 포기하고 영원히 무(無)의 세계로 동화되어 버린 자의 유품입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('천사의 깃털 같은 카본 조각', '장비병 환자들조차 본 적 없는, 무게가 마이너스(-) 영역에 도달하여 만지면 오히려 몸이 하늘로 뜨게 되는 신의 부품입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0),
  ('궁극의 깨달음', '''나는 달린다, 고로 존재한다''는 명제를 넘어, ''내가 달리는 것이 아니라 세상이 나를 스쳐 지나가는 것이다''라는 득도의 순간입니다.', 'item', 'common', '2a8f481e-77ba-1876-c15c-5fc9965189f4', 1.0)
